function _mastersGetBootstrapFromView_() {
  const rows = supabaseSelect('v_client_master_register', {
    order: 'client_name.asc',
    limit: 3000
  }) || [];
  return rows.map(_mastersClientPayloadFromView_);
}

function _mastersCacheVersion_() {
  return PropertiesService.getScriptProperties().getProperty('MASTERS_CACHE_VERSION') || '0';
}

function _touchMastersCacheVersion_() {
  PropertiesService.getScriptProperties().setProperty('MASTERS_CACHE_VERSION', String(Date.now()));
}

function _requireMastersWriteAccess_(token, preferredAction) {
  const user = getSessionUser(token);
  if (!user) throw new Error('Unauthorized');
  if (String(user.role || '').toUpperCase() === 'ADMIN') return user;
  if (_userHasPermission_(user, 'MASTERS', preferredAction || 'can_edit')) return user;
  if (_userHasPermission_(user, 'MASTERS', 'can_edit')) return user;
  if (_userHasPermission_(user, 'MASTERS', 'can_create')) return user;
  // Compatibility for roles created before Masters write flags were assigned.
  if (_userHasPermission_(user, 'MASTERS', 'can_view')) return user;
  throw new Error('Unauthorized');
}

function _clientNormalizePartyPayloadRows_(clientRecord, payload) {
  const rows = Array.isArray(payload && payload.parties) ? payload.parties : [];
  const normalized = rows.map(function(row) {
    const src = row || {};
    const gstin = String(src.gstin || '').trim().toUpperCase();
    const derivedPan = gstin.length >= 12 ? gstin.slice(2, 12) : '';
    const panNo = String(src.panNo || derivedPan || '').trim().toUpperCase();
    return {
      id: String(src.id || Utilities.getUuid()).trim(),
      client_id: clientRecord.id,
      client_code: clientRecord.clientCode,
      party_name: String(src.partyName || '').trim(),
      address_type: String(src.addressType || '').trim().toUpperCase(),
      label: String(src.label || '').trim(),
      address_line1: String(src.addressLine1 || '').trim(),
      address_line2: String(src.addressLine2 || '').trim(),
      city: String(src.city || '').trim(),
      state: String(src.state || '').trim(),
      pincode: String(src.pincode || '').trim(),
      gstin: gstin,
      pan_no: panNo,
      payment_terms: String(src.paymentTerms || '').trim(),
      contact_person: String(src.contactPerson || '').trim(),
      contact_phone: String(src.contactPhone || '').trim(),
      is_default: src.isDefault === true,
      active: src.active === false ? false : true
    };
  }).filter(function(row) {
    return row.party_name || row.address_line1 || row.city || row.state || row.pincode || row.gstin || row.label;
  });

  if (!normalized.length) {
    throw new Error('At least one Bill To or Ship To row is required.');
  }

  normalized.forEach(function(row, idx) {
    if (!row.party_name) throw new Error('Party name is required in address row ' + (idx + 1) + '.');
    if (!['BILL_TO', 'SHIP_TO'].includes(row.address_type)) {
      throw new Error('Address type must be BILL_TO or SHIP_TO in row ' + (idx + 1) + '.');
    }
    if (!row.address_line1) throw new Error('Address line 1 is required in row ' + (idx + 1) + '.');
    if (!row.state) throw new Error('State is required in row ' + (idx + 1) + '.');
  });

  const billDefaults = normalized.filter(function(row){ return row.address_type === 'BILL_TO' && row.is_default; }).length;
  const shipDefaults = normalized.filter(function(row){ return row.address_type === 'SHIP_TO' && row.is_default; }).length;
  if (!normalized.some(function(row){ return row.address_type === 'BILL_TO'; })) throw new Error('At least one BILL_TO row is required.');
  if (!normalized.some(function(row){ return row.address_type === 'SHIP_TO'; })) throw new Error('At least one SHIP_TO row is required.');
  if (billDefaults > 1) throw new Error('Only one default BILL_TO row is allowed.');
  if (shipDefaults > 1) throw new Error('Only one default SHIP_TO row is allowed.');

  if (billDefaults === 0) {
    const firstBill = normalized.find(function(row){ return row.address_type === 'BILL_TO'; });
    if (firstBill) firstBill.is_default = true;
  }
  if (shipDefaults === 0) {
    const firstShip = normalized.find(function(row){ return row.address_type === 'SHIP_TO'; });
    if (firstShip) firstShip.is_default = true;
  }

  return normalized;
}

function mastersGetBootstrap(token) {
  _requireModuleAccess_(token, 'MASTERS', 'can_view');
  const cacheKey = _cacheKeyHash_('MASTERS_BOOTSTRAP', _mastersCacheVersion_());
  const cached = _getCachedJson_(cacheKey);
  if (cached) return cached;
  try {
    const resultFromView = {
      ok: true,
      source: 'view',
      clients: _mastersGetBootstrapFromView_()
    };
    _putCachedJson_(cacheKey, resultFromView, 180);
    return resultFromView;
  } catch (viewErr) {
    Logger.log('mastersGetBootstrap view fallback: ' + ((viewErr && viewErr.message) || viewErr));
  }

  const clients = _clientSelectRows_({
    order: 'client_name.asc',
    limit: 2000
  }) || [];
  const clientIds = clients.map(function(row){ return row.id; }).filter(Boolean);
  const partyMap = {};
  if (clientIds.length) {
    try {
      (_clientPartySelectRowsByClientIds_(clientIds, 'client_id.asc,address_type.asc,is_default.desc,label.asc,party_name.asc') || []).forEach(function(row) {
        const key = String(row.client_id || '');
        if (!partyMap[key]) partyMap[key] = [];
        partyMap[key].push(row);
      });
    } catch (err) {
      Logger.log('mastersGetBootstrap client_parties load failed: ' + ((err && err.message) || err));
    }
  }
  const result = {
    ok: true,
    source: 'fallback',
    clients: clients.map(function(row) {
      const parties = partyMap[String(row.id || '')] || [];
      return {
        id: row.id,
        clientCode: row.client_code || '',
        clientName: row.client_name || '',
        state: row.state || '',
        gstin: row.gstin || '',
        panNo: row.pan_no || '',
        creditDays: Number(row.credit_days || 0),
        category: row.category || '',
        paymentTerms: row.payment_terms || '',
        active: row.active !== false,
        parties: parties.map(function(party) {
          return {
            id: party.id,
            partyName: party.party_name || '',
            addressType: party.address_type || '',
            label: party.label || '',
            addressLine1: party.address_line1 || '',
            addressLine2: party.address_line2 || '',
            city: party.city || '',
            state: party.state || '',
            pincode: party.pincode || '',
            gstin: party.gstin || '',
            panNo: party.pan_no || '',
            paymentTerms: party.payment_terms || '',
            contactPerson: party.contact_person || '',
            contactPhone: party.contact_phone || '',
            isDefault: party.is_default === true,
            active: party.active !== false
          };
        })
      };
    })
  };
  _putCachedJson_(cacheKey, result, 180);
  return result;
}

function mastersSaveClient(payload, token) {
  if (!payload) throw new Error('Client payload is required.');

  const existing = String(payload.id || '').trim()
    ? (_clientSelectRows_({
        filters: { id: 'eq.' + String(payload.id).trim() },
        limit: 1
      }) || [])[0]
    : null;
  _requireMastersWriteAccess_(token, existing ? 'can_edit' : 'can_create');
  const record = _clientNormalizePayload_(payload, existing);

  if (!record.clientCode) throw new Error('Client code is required.');
  if (!record.clientName) throw new Error('Client name is required.');
  if (!existing) {
    const duplicate = (_clientSelectRows_({
      filters: { client_code: 'eq.' + record.clientCode },
      limit: 1
    }) || [])[0];
    if (duplicate) throw new Error('Client code already exists: ' + record.clientCode);
  }
  const partyRows = _clientNormalizePartyPayloadRows_(record, payload);

  const dbRow = {
    id: record.id,
    client_code: record.clientCode,
    client_name: record.clientName,
    state: record.state || null,
    gstin: record.gstin || null,
    credit_days: record.creditDays,
    category: record.category || null,
    active: record.active,
    pan_no: record.panNo || null,
    payment_terms: record.paymentTerms || null
  };

  if (existing && existing.id) {
    supabaseUpdate('clients', { id: 'eq.' + existing.id }, dbRow);
    supabaseDelete('client_parties', { client_id: 'eq.' + existing.id });
  } else {
    supabaseInsert('clients', dbRow);
  }

  supabaseBulkInsert('client_parties', partyRows.map(function(row) {
    return {
      id: row.id,
      client_id: row.client_id,
      client_code: row.client_code,
      party_name: row.party_name,
      address_type: row.address_type,
      label: row.label || null,
      address_line1: row.address_line1,
      address_line2: row.address_line2 || null,
      city: row.city || null,
      state: row.state,
      pincode: row.pincode || null,
      gstin: row.gstin || null,
      pan_no: row.pan_no || null,
      payment_terms: row.payment_terms || null,
      contact_person: row.contact_person || null,
      contact_phone: row.contact_phone || null,
      is_default: row.is_default === true,
      active: row.active !== false
    };
  }));

  _touchMastersCacheVersion_();
  return { ok: true };
}

function mastersToggleClientStatus(clientId, active, token) {
  _requireMastersWriteAccess_(token, 'can_edit');
  const id = String(clientId || '').trim();
  if (!id) throw new Error('Client id is required.');
  supabaseUpdate('clients', { id: 'eq.' + id }, { active: active === true });
  _touchMastersCacheVersion_();
  return { ok: true };
}

/******************************************************
 * PLATES & DIES — BACKEND (SINGLE DB: DB_SalesOrders)
 * PowerForge ERP
 ******************************************************/

/**
 * Helper: derive procurement status
 */
/**
 * READ — Plates & Dies jobs
 * Only SO lines where Plate OR Die = NEW
 */
function _purchaseIsArtworkToolingNew_(value) {
  const status = String(value || '').trim().toUpperCase();
  if (!status) return false;
  return status === 'NEW' ||
    status === 'YES' ||
    status === 'REQUIRED' ||
    status === 'SELECTED' ||
    /\bNEW\b/.test(status);
}

function _purchaseSplitCsvList_(value) {
  if (Array.isArray(value)) return value.map(function(v) { return String(v || '').trim(); }).filter(Boolean);
  return String(value || '')
    .split(',')
    .map(function(v) { return String(v || '').trim(); })
    .filter(Boolean);
}

function _purchaseNormalizeToolingWorkbenchRow_(row) {
  const soList = Array.isArray(row.so_list) ? row.so_list.filter(Boolean) : _purchaseSplitCsvList_(row.so);
  const lineList = Array.isArray(row.line_list) ? row.line_list.map(function(v) { return String(v || '').trim(); }).filter(Boolean) : _purchaseSplitCsvList_(row.line_no);
  const woList = Array.isArray(row.wo_list) ? row.wo_list.filter(Boolean) : _purchaseSplitCsvList_(row.wo_nos);
  const clientList = Array.isArray(row.client_list) ? row.client_list.filter(Boolean) : _purchaseSplitCsvList_(row.client);
  const productList = Array.isArray(row.product_list) ? row.product_list.filter(Boolean) : String(row.product_name || '').split('/').map(function(v) { return String(v || '').trim(); }).filter(Boolean);
  const memberRefs = Array.isArray(row.member_refs) ? row.member_refs : [];
  return {
    id: row.id || row.artwork_key || '',
    artworkKey: row.artwork_key || row.id || '',
    artworkNo: String(row.artwork_no || '').trim() || 'UNASSIGNED',
    so: soList.join(', '),
    soDate: row.so_date || '',
    lineNo: lineList.join(', '),
    woNos: woList.join(', '),
    client: clientList.join(', '),
    productName: productList.join(' / '),
    qty: Number(row.qty || 0),
    unit: row.unit || '',
    artworkUps: Number(row.artwork_ups || 0) || 1,
    memberRefs: memberRefs.map(function(ref) {
      return {
        soId: ref.soId || ref.so_id || '',
        soNo: ref.soNo || ref.so_no || '',
        lineNo: ref.lineNo || ref.line_no || '',
        artworkNo: ref.artworkNo || ref.artwork_no || '',
        sheetUps: Number(ref.sheetUps || ref.sheet_ups || 0) || 1
      };
    }),
    plateStatusRaw: row.plate_status_raw || '',
    dieStatusRaw: row.die_status_raw || '',
    plateIsNew: row.plate_is_new === true,
    dieIsNew: row.die_is_new === true,
    plateRequirementStatus: row.plate_requirement_status || '',
    dieRequirementStatus: row.die_requirement_status || '',
    plateActionRequired: row.plate_action_required === true,
    dieActionRequired: row.die_action_required === true,
    plateVendor: row.plate_vendor || '',
    plateOrderedOn: row.plate_ordered_on || '',
    plateReceivedOn: row.plate_received_on || '',
    plateChallanNo: row.plate_challan_no || '',
    plateSize: row.plate_size || '',
    plateCount: row.plate_count ?? '',
    hybridPlateCount: row.hybrid_plate_count ?? '',
    hybridPlateSize: row.hybrid_plate_size || '',
    plateCost: row.plate_cost || '',
    plateOrderedQty: Number(row.plate_ordered_qty || 0),
    plateReceivedQty: Number(row.plate_received_qty || 0),
    platePendingQty: Number(row.plate_pending_qty || 0),
    platePORefs: _purchaseSplitCsvList_(row.plate_po_refs),
    statusPlate: row.status_plate || '',
    dieVendor: row.die_vendor || '',
    dieOrderedOn: row.die_ordered_on || '',
    dieReceivedOn: row.die_received_on || '',
    dieChallanNo: row.die_challan_no || '',
    dieCount: row.die_count ?? '',
    dieCost: row.die_cost || '',
    dieOrderedQty: Number(row.die_ordered_qty || 0),
    dieReceivedQty: Number(row.die_received_qty || 0),
    diePendingQty: Number(row.die_pending_qty || 0),
    diePORefs: _purchaseSplitCsvList_(row.die_po_refs),
    statusDie: row.status_die || '',
    soList: soList,
    lineList: lineList,
    woList: woList,
    clientList: clientList,
    productList: productList,
    soCount: Number(row.so_count || soList.length || 0)
  };
}

function getPlateDieJobs(opts = {}) {
  const cacheKey = _reportsCacheKey_('PLATE_DIE_JOBS', { source: 'purchase-tooling-register-v1', opts: opts || {} });
  const cached = _getCachedJson_(cacheKey);
  if (cached) return cached;
  const type = String(opts.type || 'ALL').toUpperCase();
  let groupedRows = [];
  let workbenchViewAvailable = false;
  try {
    const viewFilters = {};
    const artworkKeys = Array.isArray(opts.artworkKeys) ? opts.artworkKeys.map(function(v) { return String(v || '').trim(); }).filter(Boolean) : [];
    if (artworkKeys.length) viewFilters.artwork_key = _supabaseInFilter_(artworkKeys);
    if (opts.pendingOnly === true) {
      if (type === 'DIE') viewFilters.die_action_required = 'eq.true';
      else if (type === 'PLATE') viewFilters.plate_action_required = 'eq.true';
      else viewFilters.or = '(plate_action_required.eq.true,die_action_required.eq.true)';
    } else {
      if (opts.fromDate && opts.toDate) {
        viewFilters.and = '(so_date.gte.' + opts.fromDate + ',so_date.lte.' + opts.toDate + ')';
      } else if (opts.fromDate) {
        viewFilters.so_date = 'gte.' + opts.fromDate;
      } else if (opts.toDate) {
        viewFilters.so_date = 'lte.' + opts.toDate;
      }
    }
    groupedRows = _supabaseSelectAll_('v_purchase_tooling_workbench', {
      select: '*',
      filters: viewFilters,
      order: 'so_date.asc,artwork_no.asc'
    }, 1000, 50000) || [];
    workbenchViewAvailable = true;
  } catch (err) {
    const msg = String(err && err.message || err || '');
    if (msg.indexOf('plate_action_required') !== -1 || msg.indexOf('die_action_required') !== -1) {
      try {
        groupedRows = _supabaseSelectAll_('v_purchase_tooling_workbench', {
          select: '*',
          order: 'so_date.asc,artwork_no.asc'
        }, 1000, 50000) || [];
        workbenchViewAvailable = true;
      } catch (fallbackErr) {
        Logger.log('Purchase tooling workbench view unavailable: ' + (fallbackErr && fallbackErr.message ? fallbackErr.message : fallbackErr));
        groupedRows = [];
      }
    } else {
      Logger.log('Purchase tooling workbench view unavailable: ' + msg);
      groupedRows = [];
    }
  }
  if (workbenchViewAvailable) {
    const wantedArtworkKeys = Array.isArray(opts.artworkKeys) ? opts.artworkKeys.map(function(v) { return String(v || '').trim(); }).filter(Boolean) : [];
    const wantedArtworkMap = {};
    wantedArtworkKeys.forEach(function(key) { wantedArtworkMap[key] = true; });
    const resultFromView = groupedRows
      .map(_purchaseNormalizeToolingWorkbenchRow_)
      .filter(function(row) {
        if (wantedArtworkKeys.length && !wantedArtworkMap[String(row.artworkKey || row.id || '').trim()]) return false;
        if (!opts || !Object.keys(opts).length) return true;
        if (opts.pendingOnly) {
          const plateStatus = String(row.statusPlate || '').toUpperCase();
          const dieStatus = String(row.statusDie || '').toUpperCase();
          const platePending = row.plateActionRequired === true || ((row.plateIsNew === true || _purchaseIsArtworkToolingNew_(row.plateStatusRaw)) && plateStatus !== 'RECEIVED' && plateStatus !== 'NA') || plateStatus === 'ORDERED' || plateStatus === 'PARTIAL';
          const diePending = row.dieActionRequired === true || ((row.dieIsNew === true || _purchaseIsArtworkToolingNew_(row.dieStatusRaw)) && dieStatus !== 'RECEIVED' && dieStatus !== 'NA') || dieStatus === 'ORDERED' || dieStatus === 'PARTIAL';
          if (type === 'PLATE') return platePending;
          if (type === 'DIE') return diePending;
          return platePending || diePending;
        }
        const rowDate = row.soDate ? new Date(row.soDate) : null;
        if (opts.fromDate && rowDate && rowDate < new Date(opts.fromDate + 'T00:00:00')) return false;
        if (opts.toDate && rowDate && rowDate > new Date(opts.toDate + 'T23:59:59')) return false;
        return true;
      });
    _putCachedJson_(cacheKey, resultFromView, 180);
    return resultFromView;
  }

  let viewRows = [];
  try {
    viewRows = selectArtworkJobsView_({
      select: 'id,so_number,so_date,line_no,client_name,product_name,qty,unit,artwork_no,sheet_ups,plate_status,die_status,plate_size,plate_count,has_hybrid_plate,hybrid_plate_size,hybrid_plate_count,die_count',
      order: 'so_date.asc,so_number.asc,line_no.asc'
    }) || [];
  } catch (err) {
    viewRows = [];
  }

  if (!viewRows.length) return [];

  const toolingRows = _reportsTrySelect_('v_report_planning_tooling_status', {
    order: 'so_number.asc,line_no.asc'
  }) || [];
  const toolingMap = {};
  toolingRows.forEach(function(row) {
    const key = String(row.so_number || '') + '||' + String(row.line_no || '');
    toolingMap[key] = row;
  });

  const grouped = {};
  viewRows.forEach(function(a) {
    const key = String(a.artwork_no || '').trim() || (String(a.id || '') + '||' + String(a.line_no || ''));
    const tool = toolingMap[String(a.so_number || '') + '||' + String(a.line_no || '')] || {};
    const rowPlateNew = _purchaseIsArtworkToolingNew_(a.plate_status);
    const rowDieNew = _purchaseIsArtworkToolingNew_(a.die_status);

    if (!grouped[key]) {
      grouped[key] = {
        id: key,
        artworkKey: key,
        artworkNo: String(a.artwork_no || '').trim() || 'UNASSIGNED',
        so: [],
        soDate: a.so_date || '',
        lineNo: [],
        woNos: [],
        client: [],
        productName: [],
        qty: 0,
        unit: a.unit || '',
        artworkUps: Number(a.sheet_ups || 0) || 1,
        memberRefs: [],
        plateStatusRaw: a.plate_status,
        dieStatusRaw: a.die_status,
        plateIsNew: false,
        dieIsNew: false,
        plateVendor: tool.plate_vendors || '',
        plateOrderedOn: tool.plate_ordered_on || '',
        plateReceivedOn: tool.plate_received_on || '',
        plateChallanNo: tool.plate_receipt_refs || '',
        plateSize: a.plate_size || '',
        plateCount: a.plate_count ?? '',
        hybridPlateCount: a.hybrid_plate_count ?? '',
        hybridPlateSize: a.hybrid_plate_size || '',
        plateCost: '',
        plateOrderedQty: Number(tool.plate_ordered_qty || 0),
        plateReceivedQty: Number(tool.plate_received_qty || 0),
        platePendingQty: Number(tool.plate_pending_qty || 0),
        platePORefs: String(tool.plate_po_nos || '').trim() ? String(tool.plate_po_nos).split(',').map(function(v){ return String(v || '').trim(); }).filter(Boolean) : [],
        statusPlate: tool.plate_procurement_status || _purchaseArtworkPOStatus_(tool.plate_ordered_qty || 0, tool.plate_received_qty || 0),
        dieVendor: tool.die_vendors || '',
        dieOrderedOn: tool.die_ordered_on || '',
        dieReceivedOn: tool.die_received_on || '',
        dieChallanNo: tool.die_receipt_refs || '',
        dieCount: a.die_count ?? '',
        dieCost: '',
        dieOrderedQty: Number(tool.die_ordered_qty || 0),
        dieReceivedQty: Number(tool.die_received_qty || 0),
        diePendingQty: Number(tool.die_pending_qty || 0),
        diePORefs: String(tool.die_po_nos || '').trim() ? String(tool.die_po_nos).split(',').map(function(v){ return String(v || '').trim(); }).filter(Boolean) : [],
        statusDie: tool.die_procurement_status || _purchaseArtworkPOStatus_(tool.die_ordered_qty || 0, tool.die_received_qty || 0)
      };
    }

    const row = grouped[key];
    row.plateIsNew = row.plateIsNew || rowPlateNew;
    row.dieIsNew = row.dieIsNew || rowDieNew;
    if (rowPlateNew) row.plateStatusRaw = a.plate_status || row.plateStatusRaw;
    if (rowDieNew) row.dieStatusRaw = a.die_status || row.dieStatusRaw;
    if (rowPlateNew) {
      if (!String(row.plateSize || '').trim() && String(a.plate_size || '').trim()) row.plateSize = a.plate_size;
      if (!(Number(row.plateCount || 0) > 0) && Number(a.plate_count || 0) > 0) row.plateCount = a.plate_count;
      if (!(Number(row.hybridPlateCount || 0) > 0) && Number(a.hybrid_plate_count || 0) > 0) row.hybridPlateCount = a.hybrid_plate_count;
      if (!String(row.hybridPlateSize || '').trim() && String(a.hybrid_plate_size || '').trim()) row.hybridPlateSize = a.hybrid_plate_size;
    }
    if (rowDieNew && !(Number(row.dieCount || 0) > 0) && Number(a.die_count || 0) > 0) row.dieCount = a.die_count;
    if (a.so_number && row.so.indexOf(a.so_number) === -1) row.so.push(a.so_number);
    if (String(a.line_no || '') && row.lineNo.indexOf(String(a.line_no || '')) === -1) row.lineNo.push(String(a.line_no || ''));
    if (a.product_name && row.productName.indexOf(a.product_name) === -1) row.productName.push(a.product_name);
    row.qty += Number(a.qty || 0);
    row.memberRefs.push({
      soId: a.id,
      soNo: a.so_number || '',
      lineNo: a.line_no,
      artworkNo: a.artwork_no || '',
      sheetUps: Number(a.sheet_ups || 0) || 1
    });
  });

  const result = Object.keys(grouped).map(function(key) {
    const row = grouped[key];
    row.soList = row.so.slice();
    row.lineList = row.lineNo.slice();
    row.woList = row.woNos.slice();
    row.clientList = row.client.slice();
    row.productList = row.productName.slice();
    row.soCount = row.so.length;
    row.so = row.so.join(', ');
    row.lineNo = row.lineNo.join(', ');
    row.woNos = row.woNos.join(', ');
    row.client = row.client.join(', ');
    row.productName = row.productName.join(' / ');
    return row;
  }).filter(function(row) {
    if (!opts || !Object.keys(opts).length) return true;
    if (opts.pendingOnly) {
      const plateStatus = String(row.statusPlate || '').toUpperCase();
      const dieStatus = String(row.statusDie || '').toUpperCase();
      const platePending = (row.plateIsNew === true || _purchaseIsArtworkToolingNew_(row.plateStatusRaw)) && plateStatus !== 'RECEIVED' && plateStatus !== 'NA';
      const diePending = (row.dieIsNew === true || _purchaseIsArtworkToolingNew_(row.dieStatusRaw)) && dieStatus !== 'RECEIVED' && dieStatus !== 'NA';
      if (String(opts.type || '').toUpperCase() === 'PLATE') return platePending;
      if (String(opts.type || '').toUpperCase() === 'DIE') return diePending;
      return platePending || diePending;
    }
    const rowDate = row.soDate ? new Date(row.soDate) : null;
    if (opts.fromDate && rowDate && rowDate < new Date(opts.fromDate + 'T00:00:00')) return false;
    if (opts.toDate && rowDate && rowDate > new Date(opts.toDate + 'T23:59:59')) return false;
    return true;
  });

  _putCachedJson_(cacheKey, result, 180);
  return result;
}

