function purchaseSearchToolingRegister(payload) {
  const p = payload || {};
  const artworkText = String(p.artworkText || '').trim();
  const q = String(p.q || '').trim();
  const type = String(p.type || 'ALL').trim().toUpperCase();
  const reqStatus = String(p.requirementStatus || '').trim().toUpperCase();
  const poStatus = String(p.purchaseStatus || '').trim().toUpperCase();
  const fromDate = String(p.fromDate || '').trim();
  const toDate = String(p.toDate || '').trim();
  const limit = Math.min(200, Math.max(1, Number(p.limit || 100) || 100));
  if (!artworkText && !q && !reqStatus && !poStatus && !fromDate && !toDate) {
    return { ok: true, rows: [], message: 'Enter search text or select a filter to load tooling register rows.' };
  }

  const filters = {};
  const searchClauses = [];
  if (artworkText) {
    const artworkPattern = '*' + artworkText.replace(/[(),]/g, ' ').replace(/\s+/g, ' ').trim().replace(/\*/g, '') + '*';
    searchClauses.push('artwork_no.ilike.' + artworkPattern);
  }
  if (q) {
    const term = q.replace(/[(),]/g, ' ').replace(/\s+/g, ' ').trim();
    if (term) {
      const pattern = '*' + term.replace(/\*/g, '') + '*';
      searchClauses.push.apply(searchClauses, [
        'so.ilike.' + pattern,
        'line_no.ilike.' + pattern,
        'client.ilike.' + pattern,
        'product_name.ilike.' + pattern,
        'plate_vendor.ilike.' + pattern,
        'die_vendor.ilike.' + pattern,
        'plate_po_refs.ilike.' + pattern,
        'die_po_refs.ilike.' + pattern,
        'plate_challan_no.ilike.' + pattern,
        'die_challan_no.ilike.' + pattern
      ]);
    }
  }
  if (searchClauses.length) filters.or = '(' + searchClauses.join(',') + ')';
  if (fromDate && toDate) filters.and = '(so_date.gte.' + fromDate + ',so_date.lte.' + toDate + ')';
  else if (fromDate) filters.so_date = 'gte.' + fromDate;
  else if (toDate) filters.so_date = 'lte.' + toDate;
  if (reqStatus) {
    if (type === 'DIE') filters.die_requirement_status = 'eq.' + reqStatus;
    else if (type === 'PLATE') filters.plate_requirement_status = 'eq.' + reqStatus;
  }
  if (poStatus) {
    if (type === 'DIE') filters.status_die = 'eq.' + poStatus;
    else if (type === 'PLATE') filters.status_plate = 'eq.' + poStatus;
  }

  const rows = _supabaseSelectAll_('v_purchase_tooling_register_search', {
    select: '*',
    filters: filters,
    order: 'so_date.desc,artwork_no.asc',
    limit: limit
  }, Math.min(200, limit), limit) || [];

  return {
    ok: true,
    rows: rows.map(_purchaseNormalizeToolingWorkbenchRow_),
    limit: limit,
    truncated: rows.length >= limit
  };
}

/**
 * SAVE — Plate & Die procurement details (bulk)
 * rows: [{ id, plateVendor, platePO, ... , dieCost, updatedBy }]
 */
function savePlateDieBulk(rows) {
  if (!Array.isArray(rows) || !rows.length) {
    return { ok: true, updated: 0 };
  }

  let updated = 0;

  rows.forEach(p => {
    const artworkKey = String(p.artworkKey || p.id || '').trim();
    if (!artworkKey) return;
    const artworkNo = String(p.artworkNo || '').trim() || null;

    const upsertRow = function(type, payload) {
      const hasAnyValue = [
        payload.vendor,
        payload.ordered_on,
        payload.received_on,
        payload.challan_no,
        payload.count,
        payload.cost,
        payload.plate_size,
        payload.plate_count,
        payload.hybrid_plate_count,
        payload.hybrid_plate_size,
        payload.die_count
      ].some(v => !(v === '' || v === null || typeof v === 'undefined'));

      if (!hasAnyValue) return false;

      let existing = null;
      try {
        existing = supabaseSelect('purchase_artwork_procurement', {
          filters: {
            artwork_key: 'eq.' + artworkKey,
            type: 'eq.' + type
          },
          limit: 1
        })[0];
      } catch (e) {
        throw new Error('Run purchase_module_updates_20260317.sql in Supabase before saving artwork-wise plate/die entries.');
      }

      const finalPayload = {
        artwork_key: artworkKey,
        artwork_no: artworkNo,
        type: type,
        vendor: payload.vendor || '',
        ordered_on: payload.ordered_on || null,
        received_on: payload.received_on || null,
        challan_no: payload.challan_no || '',
        count: payload.count === '' ? null : (payload.count ?? null),
        cost: payload.cost === '' ? null : (payload.cost ?? null),
        plate_size: payload.plate_size || null,
        plate_count: payload.plate_count === '' ? null : (payload.plate_count ?? null),
        hybrid_plate_count: payload.hybrid_plate_count === '' ? null : (payload.hybrid_plate_count ?? null),
        hybrid_plate_size: payload.hybrid_plate_size || null,
        die_count: payload.die_count === '' ? null : (payload.die_count ?? null),
        status: 'ACTIVE',
        updated_at: new Date().toISOString()
      };

      try {
        if (existing?.id) {
          supabaseUpdate(
            'purchase_artwork_procurement',
            { id: 'eq.' + existing.id },
            finalPayload
          );
        } else {
          finalPayload.created_at = new Date().toISOString();
          supabaseInsert('purchase_artwork_procurement', finalPayload);
        }
      } catch (e) {
        throw new Error('Run purchase_plate_die_po_schema.sql in Supabase before saving the updated plate and die planning fields.');
      }
      return true;
    };

    if (upsertRow('PLATE', {
      vendor: p.plateVendor,
      ordered_on: p.plateOrderedOn,
      received_on: p.plateReceivedOn,
      challan_no: p.plateChallanNo,
      count: p.plateCount,
      cost: p.plateCost,
      plate_size: p.plateSize,
      plate_count: p.plateCount,
      hybrid_plate_count: p.hybridPlateCount,
      hybrid_plate_size: p.hybridPlateSize
    })) {
      updated++;
    }

    if (upsertRow('DIE', {
      vendor: p.dieVendor,
      ordered_on: p.dieOrderedOn,
      received_on: p.dieReceivedOn,
      challan_no: p.dieChallanNo,
      count: p.dieCount,
      cost: p.dieCost,
      die_count: p.dieCount
    })) {
      updated++;
    }
  });

  PropertiesService.getScriptProperties().setProperty('PURCHASE_CACHE_VERSION', String(Date.now()));
  return { ok: true, updated };
}

