function _purchaseIsCancelledStatus_(status) {
  return String(status || '').trim().toUpperCase() === 'CANCELLED';
}

function _purchaseParsePOShortClose_(remarks) {
  const text = String(remarks || '');
  const matches = text.match(/\[PO_SHORT_CLOSE[^\]]*\]/gi) || [];
  if (!matches.length) {
    return { isShortClosed: false, qty: 0, raw: '' };
  }
  const raw = matches[matches.length - 1];
  const qtyMatch = raw.match(/qty=([0-9.]+)/i);
  return {
    isShortClosed: true,
    qty: qtyMatch ? Math.max(0, Number(qtyMatch[1] || 0)) : 0,
    raw: raw
  };
}

function _purchasePOLineShortClosedQty_(line, receivedQty) {
  const parsed = _purchaseParsePOShortClose_(line && line.remarks);
  if (!parsed.isShortClosed) return 0;
  const ordered = Number(line && line.qty || 0);
  const received = Number(receivedQty || 0);
  const remaining = Math.max(0, ordered - received);
  return Math.min(remaining, parsed.qty > 0 ? parsed.qty : remaining);
}

function _purchaseDerivePOStatusWithShortClose_(totalQty, receivedQty, shortClosedQty) {
  const ordered = Number(totalQty || 0);
  const received = Number(receivedQty || 0);
  const shortClosed = Number(shortClosedQty || 0);
  const pending = Math.max(0, ordered - received - shortClosed);
  if (ordered <= 0) return 'OPEN';
  if (pending <= 0 && received >= ordered - 0.0001) return 'RECEIVED';
  if (pending <= 0 && shortClosed > 0) return 'SHORT_CLOSED';
  if (received > 0) return 'PARTIAL';
  return 'OPEN';
}

function _purchaseBuildActivePRPoLineMap_(prNos, receiptSeed) {
  const wanted = Array.isArray(prNos)
    ? new Set(prNos.map(function(v) { return String(v || '').trim(); }).filter(Boolean))
    : null;
  const headerMap = {};
  const headerByNo = {};
  _purchaseListPOHeaders_().forEach(function(header) {
    if (header.id) headerMap[String(header.id)] = header;
    if (header.poNo) headerByNo[String(header.poNo)] = header;
  });

  const result = {};
  const activeLines = _purchaseListPOLines_()
    .filter(function(line) {
      if (String(line.sourceType || '').toUpperCase() !== 'INVENTORY_PR') return false;
      const prNo = String(line.sourceRef || '').trim();
      if (!prNo) return false;
      if (wanted && !wanted.has(prNo)) return false;
      const header = headerMap[String(line.poId || '')] || headerByNo[String(line.poNo || '')] || {};
      return !_purchaseIsCancelledStatus_(header.status);
    })
    .sort(function(a, b) {
      return String(a.createdAt || '').localeCompare(String(b.createdAt || '')) ||
        Number(a.lineNo || 0) - Number(b.lineNo || 0);
    });
  const receiptEntriesByLine = {};
  _purchaseListPOReceipts_().forEach(function(row) {
    const lineId = String(row.poLineId || '').trim();
    if (!lineId) return;
    if (!receiptEntriesByLine[lineId]) receiptEntriesByLine[lineId] = [];
    receiptEntriesByLine[lineId].push(row);
  });
  const linesWithoutLinkedReceipt = activeLines.filter(function(line) {
    return !(receiptEntriesByLine[String(line.id || '').trim()] || []).length;
  });
  const ledgerReceiptEntriesByLine = _purchaseLedgerPOReceiptEntriesByLine_(linesWithoutLinkedReceipt);

  activeLines.forEach(function(line) {
      const prNo = String(line.sourceRef || '').trim();
      const lineId = String(line.id || '').trim();
      const linkedEntries = receiptEntriesByLine[lineId] || [];
      const fallbackEntries = ledgerReceiptEntriesByLine[lineId] || [];
      const receiptEntries = linkedEntries.length ? linkedEntries : fallbackEntries;
      const allocated = receiptEntries.reduce(function(sum, row) {
        return sum + Number(row.qty || 0);
      }, 0);
      const shortClosedQty = _purchasePOLineShortClosedQty_(line, allocated);
      if (!result[prNo]) {
        result[prNo] = { orderedQty: 0, openPOQty: 0, refs: [], latestRate: 0, latestTaxPct: 0 };
      }
      result[prNo].orderedQty += Number(line.qty || 0);
      result[prNo].openPOQty += Math.max(0, Number(line.qty || 0) - allocated - shortClosedQty);
      result[prNo].latestRate = Number(line.rate || 0) || result[prNo].latestRate;
      result[prNo].latestTaxPct = Number(line.taxPct || 0) || result[prNo].latestTaxPct;
      if (line.poNo && result[prNo].refs.indexOf(line.poNo) === -1) {
        result[prNo].refs.push(line.poNo);
      }
    });
  return result;
}

function _purchaseListPOReceipts_(opts) {
  opts = opts || {};
  try {
    const rows = (_supabaseSelectAll_('purchase_po_receipts', {
      order: 'receipt_date.desc,created_at.desc'
    }, 1000, 50000) || []).map(r => ({
      id: r.id,
      poId: r.po_id || '',
      poNo: r.po_no || '',
      poLineId: r.po_line_id || '',
      lineNo: Number(r.line_no || 0),
      sourceType: r.source_type || '',
      receiptDate: r.receipt_date || '',
      challanNo: r.challan_no || '',
      qty: Number(r.qty || 0),
      rate: Number(r.rate || 0),
      remarks: r.remarks || '',
      sourceRef: r.source_ref || '',
      jobRef: r.job_ref || '',
      artworkNo: r.artwork_no || '',
      soRefs: r.so_refs || '',
      createdAt: r.created_at || ''
    }));
    if (opts.includeReversed === true) {
      return rows;
    }

    const reversedRows = _supabaseSelectAll_('inv_ledger', {
      select: 'id,ref_no,ref_type,created_at',
      filters: { ref_type: 'eq.REV-PO-RECEIPT' },
      order: 'created_at.desc'
    }, 1000, 20000) || [];
    const originalIds = [...new Set(reversedRows.map(function(row) {
      return String(row.ref_no || '').trim();
    }).filter(Boolean))];
    if (!originalIds.length || !rows.length) {
      return rows;
    }

    const originalLedgerRows = [];
    const chunks = _supabaseChunkValuesByFilterLength_(originalIds, 900, 20);
    chunks.forEach(function(chunk) {
      const chunkRows = supabaseSelect('inv_ledger', {
        select: `
          id,
          item_id,
          created_at,
          ref_type,
          ref_no,
          qty_in,
          rate,
          department,
          inv_items!inv_ledger_item_id_fkey (
            item_code
          )
        `,
        filters: { id: _supabaseInFilter_(chunk) },
        order: 'created_at.asc',
        limit: 5000
      }) || [];
      chunkRows.forEach(function(row) {
        if (String(row.ref_type || '').trim().toUpperCase() === 'PO-RECEIPT') {
          originalLedgerRows.push(row);
        }
      });
    });
    if (!originalLedgerRows.length) {
      return rows;
    }

    const lineRows = _purchaseListPOLines_();
    const consumedReceiptIds = {};
    originalLedgerRows.forEach(function(ledgerRow) {
      const itemCode = String(ledgerRow?.inv_items?.item_code || '').trim();
      const candidateRows = rows.filter(function(receiptRow) {
        return !consumedReceiptIds[String(receiptRow.id || '').trim()];
      });
      const match = invFindMatchingPOReceiptRecord_(ledgerRow, itemCode, {
        receiptRows: candidateRows,
        lineRows: lineRows
      });
      if (match?.row?.id) {
        consumedReceiptIds[String(match.row.id || '').trim()] = true;
      }
    });

    return rows.filter(function(row) {
      return !consumedReceiptIds[String(row.id || '').trim()];
    });
  } catch (e) {
    Logger.log('purchase_po_receipts lookup failed: ' + e.message);
    return [];
  }
}

function _purchaseActualReceiptQtyByPR_(prNos) {
  const wanted = new Set((Array.isArray(prNos) ? prNos : [])
    .map(function(v) { return String(v || '').trim(); })
    .filter(Boolean));
  const result = {};
  wanted.forEach(function(prNo) { result[prNo] = 0; });
  if (!wanted.size) return result;

  const lineToPr = {};
  const poLines = _purchaseListPOLines_();
  poLines.forEach(function(line) {
    if (String(line.sourceType || '').trim().toUpperCase() !== 'INVENTORY_PR') return;
    const prNo = String(line.sourceRef || '').trim();
    const lineId = String(line.id || '').trim();
    if (!prNo || !lineId || !wanted.has(prNo)) return;
    lineToPr[lineId] = prNo;
  });

  const linkedReceiptLineIds = {};
  _purchaseListPOReceipts_().forEach(function(row) {
    const prNo = lineToPr[String(row.poLineId || '').trim()];
    if (!prNo) return;
    linkedReceiptLineIds[String(row.poLineId || '').trim()] = true;
    result[prNo] = Number(result[prNo] || 0) + Number(row.qty || 0);
  });

  const relevantLines = poLines.filter(function(line) {
    return !!lineToPr[String(line.id || '').trim()] && !linkedReceiptLineIds[String(line.id || '').trim()];
  });
  const ledgerEntriesByLine = _purchaseLedgerPOReceiptEntriesByLine_(relevantLines);
  Object.keys(ledgerEntriesByLine).forEach(function(lineId) {
    const prNo = lineToPr[lineId];
    if (!prNo) return;
    (ledgerEntriesByLine[lineId] || []).forEach(function(row) {
      result[prNo] = Number(result[prNo] || 0) + Number(row.qty || 0);
    });
  });

  return result;
}

function _purchaseActualReceiptQtyByPoNos_(poNos) {
  const wanted = new Set((Array.isArray(poNos) ? poNos : [])
    .map(function(v) { return String(v || '').trim(); })
    .filter(Boolean));
  const result = {};
  wanted.forEach(function(poNo) { result[poNo] = 0; });
  if (!wanted.size) return result;

  (_purchaseListPOReceipts_() || []).forEach(function(row) {
    const poNo = String(row.poNo || '').trim();
    if (wanted.has(poNo)) result[poNo] = Number(result[poNo] || 0) + Number(row.qty || 0);
  });

  try {
    const ledgerTotals = {};
    const reversedRows = _supabaseSelectAll_('inv_ledger', {
      select: 'ref_no,ref_type',
      filters: { ref_type: 'eq.REV-PO-RECEIPT' },
      order: 'created_at.desc'
    }, 1000, 20000) || [];
    const reversedLedgerIds = {};
    reversedRows.forEach(function(row) {
      const id = String(row.ref_no || '').trim();
      if (id) reversedLedgerIds[id] = true;
    });

    const list = Array.from(wanted);
    for (let i = 0; i < list.length; i += 40) {
      const chunk = list.slice(i, i + 40);
      (supabaseSelect('inv_ledger', {
        select: 'id,ref_no,ref_type,qty_in',
        filters: {
          ref_type: 'eq.PO-RECEIPT',
          ref_no: _supabaseInFilter_(chunk),
          qty_in: 'gt.0'
        },
        order: 'created_at.asc',
        limit: 5000
      }) || []).forEach(function(row) {
        const ledgerId = String(row.id || '').trim();
        if (ledgerId && reversedLedgerIds[ledgerId]) return;
        const poNo = String(row.ref_no || '').trim();
        if (wanted.has(poNo)) ledgerTotals[poNo] = Number(ledgerTotals[poNo] || 0) + Number(row.qty_in || 0);
      });
    }
    Object.keys(ledgerTotals).forEach(function(poNo) {
      result[poNo] = Math.max(Number(result[poNo] || 0), Number(ledgerTotals[poNo] || 0));
    });
  } catch (err) {
    Logger.log('PO receipt ledger lookup failed: ' + err.message);
  }
  return result;
}

function _purchaseArtworkPOStatus_(orderedQty, receivedQty) {
  const ordered = Number(orderedQty || 0);
  const received = Number(receivedQty || 0);
  const pending = Math.max(0, ordered - received);
  if (ordered <= 0) return 'PENDING';
  if (pending <= 0) return 'RECEIVED';
  if (received > 0) return 'PARTIAL';
  return 'ORDERED';
}

function _purchaseIsPlateDieSource_(sourceType) {
  const normalized = String(sourceType || '').trim().toUpperCase();
  return normalized === 'ARTWORK_PLATE' ||
    normalized === 'ARTWORK_DIE' ||
    normalized === 'DIRECT_PLATE' ||
    normalized === 'DIRECT_DIE';
}

function _purchasePlateDieTypeFromSource_(sourceType) {
  const normalized = String(sourceType || '').trim().toUpperCase();
  if (normalized === 'ARTWORK_DIE' || normalized === 'DIRECT_DIE') return 'DIE';
  if (normalized === 'ARTWORK_PLATE' || normalized === 'DIRECT_PLATE') return 'PLATE';
  return '';
}

function _purchaseReceiptHasOptionalLinkageColumnError_(err) {
  const message = String(err && err.message ? err.message : err || '');
  return /purchase_po_receipts\.(source_ref|job_ref|artwork_no|so_refs)|column "(source_ref|job_ref|artwork_no|so_refs)" of relation "purchase_po_receipts" does not exist|column purchase_po_receipts\.(source_ref|job_ref|artwork_no|so_refs) does not exist|find the '(source_ref|job_ref|artwork_no|so_refs)' column of 'purchase_po_receipts'/i.test(message);
}

function _purchaseReceiptDbRow_(row, includeOptionalLinkage) {
  const sourceRef = String(row.sourceRef || row.artworkNo || '').trim();
  const jobRef = String(row.jobRef || row.soRefs || '').trim();
  const dbRow = {
    id: row.id || Utilities.getUuid(),
    po_id: row.poId || null,
    po_no: row.poNo,
    po_line_id: row.poLineId,
    line_no: row.lineNo,
    source_type: row.sourceType,
    receipt_date: row.receiptDate || _purchaseIsoDate_(new Date()),
    challan_no: String(row.challanNo || '').trim(),
    qty: Number(row.qty || 0),
    rate: Number(row.rate || 0),
    remarks: String(row.remarks || '').trim(),
    created_at: row.createdAt || _purchaseNowIso_(),
    updated_at: row.updatedAt || _purchaseNowIso_()
  };
  if (includeOptionalLinkage !== false) {
    dbRow.source_ref = sourceRef;
    dbRow.job_ref = jobRef;
    dbRow.artwork_no = String(row.artworkNo || sourceRef || row.itemCode || '').trim();
    dbRow.so_refs = String(row.soRefs || jobRef || '').trim();
  }
  return dbRow;
}

function _purchaseInsertPOReceipt_(row) {
  try {
    supabaseInsertMinimal('purchase_po_receipts', _purchaseReceiptDbRow_(row, true));
  } catch (err) {
    if (!_purchaseReceiptHasOptionalLinkageColumnError_(err)) throw err;
    supabaseInsertMinimal('purchase_po_receipts', _purchaseReceiptDbRow_(row, false));
  }
}

function _purchaseBulkInsertPOReceipts_(rows) {
  try {
    supabaseBulkInsertMinimal('purchase_po_receipts', rows.map(function(row) {
      return _purchaseReceiptDbRow_(row, true);
    }));
  } catch (err) {
    if (!_purchaseReceiptHasOptionalLinkageColumnError_(err)) throw err;
    supabaseBulkInsertMinimal('purchase_po_receipts', rows.map(function(row) {
      return _purchaseReceiptDbRow_(row, false);
    }));
  }
}

function _purchaseReceiptRowsForPO_(poNo) {
  const key = String(poNo || '').trim();
  if (!key) return [];
  try {
    return (_supabaseSelectAll_('purchase_po_receipts', {
      filters: { po_no: 'eq.' + key },
      order: 'created_at.asc'
    }, 1000, 10000) || []).map(function(row) {
      return {
        id: row.id || '',
        poNo: row.po_no || '',
        poLineId: row.po_line_id || '',
        qty: Number(row.qty || 0),
        rate: Number(row.rate || 0),
        sourceType: row.source_type || '',
        receiptDate: row.receipt_date || '',
        challanNo: row.challan_no || '',
        remarks: row.remarks || ''
      };
    });
  } catch (err) {
    throw new Error('Unable to read plate/die receipt register. Confirm purchase_po_receipts table exists in Supabase. ' + (err.message || err));
  }
}

function _purchaseReceiptQtyByLineForPO_(poNo) {
  const result = {};
  _purchaseReceiptRowsForPO_(poNo).forEach(function(row) {
    const lineId = String(row.poLineId || '').trim();
    if (!lineId) return;
    result[lineId] = Number(result[lineId] || 0) + Number(row.qty || 0);
  });
  return result;
}

function _purchaseLedgerPOReceiptEntriesByLine_(lineRows) {
  const lines = Array.isArray(lineRows) ? lineRows : [];
  const result = {};
  if (!lines.length) return result;

  const poNos = [...new Set(lines.map(function(line) {
    return String(line.poNo || '').trim();
  }).filter(Boolean))];
  if (!poNos.length) return result;

  const reversedRows = _supabaseSelectAll_('inv_ledger', {
    select: 'ref_no,ref_type',
    filters: { ref_type: 'eq.REV-PO-RECEIPT' },
    order: 'created_at.desc'
  }, 1000, 50000) || [];
  const reversedLedgerIds = {};
  reversedRows.forEach(function(row) {
    const id = String(row.ref_no || '').trim();
    if (id) reversedLedgerIds[id] = true;
  });

  const linesByPo = {};
  lines.forEach(function(line) {
    const poNo = String(line.poNo || '').trim();
    if (!poNo) return;
    if (!linesByPo[poNo]) linesByPo[poNo] = [];
    linesByPo[poNo].push(line);
  });

  const ledgerRows = [];
  const poNoChunks = _supabaseChunkValuesByFilterLength_(poNos, 900, 20);
  poNoChunks.forEach(function(chunk) {
    const rows = supabaseSelect('inv_ledger', {
      select: `
        id,
        item_id,
        created_at,
        ref_type,
        ref_no,
        qty_in,
        rate,
        department,
        batch_no,
        remarks,
        inv_items!inv_ledger_item_id_fkey (
          item_code,
          item_name
        )
      `,
      filters: {
        ref_type: 'eq.PO-RECEIPT',
        ref_no: _supabaseInFilter_(chunk),
        qty_in: 'gt.0'
      },
      order: 'created_at.asc',
      limit: 5000
    }) || [];
    rows.forEach(function(row) {
      if (!reversedLedgerIds[String(row.id || '').trim()]) ledgerRows.push(row);
    });
  });

  const missingItemIds = [...new Set(ledgerRows.filter(function(row) {
    return !!row.item_id && (!row.inv_items || !row.inv_items.item_code);
  }).map(function(row) {
    return String(row.item_id || '').trim();
  }).filter(Boolean))];
  const fallbackItemCodeById = {};
  const missingItemChunks = _supabaseChunkValuesByFilterLength_(missingItemIds, 900, 20);
  missingItemChunks.forEach(function(chunk) {
    (supabaseSelect('inv_items', {
      select: 'id,item_code',
      filters: { id: _supabaseInFilter_(chunk) },
      limit: 500
    }) || []).forEach(function(item) {
      fallbackItemCodeById[String(item.id || '').trim()] = String(item.item_code || '').trim();
    });
  });

  ledgerRows.forEach(function(ledger) {
    const poNo = String(ledger.ref_no || '').trim();
    const candidates = linesByPo[poNo] || [];
    if (!candidates.length) return;
    const note = invParseReceiptNote_(ledger.remarks);
    const explicitLineId = String(note.POLINE || note.PO_LINE || note.POLINEID || '').trim();
    const explicitMatch = explicitLineId
      ? candidates.find(function(line) {
          return String(line.id || '').trim() === explicitLineId;
        })
      : null;
    const itemCode = String(ledger.inv_items?.item_code || fallbackItemCodeById[String(ledger.item_id || '').trim()] || '').trim().toUpperCase();
    const dept = String(ledger.department || '').trim().toUpperCase();
    const exact = candidates.filter(function(line) {
      if (itemCode && String(line.itemCode || '').trim().toUpperCase() !== itemCode) return false;
      if (dept && String(line.department || '').trim().toUpperCase() !== dept) return false;
      return true;
    });
    const itemOnly = exact.length ? exact : candidates.filter(function(line) {
      return itemCode ? String(line.itemCode || '').trim().toUpperCase() === itemCode : true;
    });
    const rateMatches = itemOnly.filter(function(line) {
      return Math.abs(Number(line.rate || 0) - Number(ledger.rate || 0)) <= 0.0001;
    });
    const qtyMatches = rateMatches.filter(function(line) {
      return Number(line.qty || 0) + 0.0001 >= Number(ledger.qty_in || 0);
    });
    const uniqueFallback = exact.length === 1 ? exact[0]
      : itemOnly.length === 1 ? itemOnly[0]
      : rateMatches.length === 1 ? rateMatches[0]
      : qtyMatches.length === 1 ? qtyMatches[0]
      : candidates.length === 1 ? candidates[0]
      : null;
    if (!explicitMatch && !uniqueFallback) {
      Logger.log('Ambiguous PO receipt ledger fallback skipped for ledger ' + ledger.id + ' / PO ' + poNo);
      return;
    }
    const match = explicitMatch || uniqueFallback;
    if (!match) return;
    const lineId = String(match.id || '').trim();
    if (!lineId) return;
    if (!result[lineId]) result[lineId] = [];
    result[lineId].push({
      id: ledger.id,
      poNo: poNo,
      poLineId: lineId,
      qty: Number(ledger.qty_in || 0),
      rate: Number(ledger.rate || 0),
      receiptDate: ledger.created_at || '',
      createdAt: ledger.created_at || '',
      sourceType: match.sourceType || '',
      sourceRef: match.sourceRef || '',
      challanNo: '',
      remarks: ledger.remarks || '',
      ledgerFallback: true
    });
  });

  return result;
}

function _purchaseNormalizeDirectLine_(line, fallbackSourceType, lineNo, poNo, now, opts) {
  opts = opts || {};
  const qty = Number(line.qty || 0);
  const rate = Number(line.rate || 0);
  const taxPct = Number(line.taxPct || 0);
  if (qty <= 0) throw new Error('Invalid PO qty for direct line ' + lineNo);
  if (rate <= 0) throw new Error('Invalid PO rate for direct line ' + lineNo);
  if (taxPct < 0) throw new Error('Invalid tax % for direct line ' + lineNo);
  const itemName = String(line.itemName || '').trim();
  if (!itemName) throw new Error('Item description is required for direct line ' + lineNo);
  const basicAmount = Number((qty * rate).toFixed(2));
  const taxAmount = Number((basicAmount * taxPct / 100).toFixed(2));
  const totalAmount = Number((basicAmount + taxAmount).toFixed(2));
  return {
    id: opts.keepId ? String(line.id || Utilities.getUuid()) : Utilities.getUuid(),
    poNo: poNo,
    lineNo: lineNo,
    sourceType: String(line.sourceType || fallbackSourceType || 'DIRECT').trim().toUpperCase(),
    sourceRef: String(line.sourceRef || '').trim(),
    itemCode: String(line.itemCode || '').trim(),
    itemName: itemName,
    qty: qty,
    rate: rate,
    taxPct: taxPct,
    amount: basicAmount,
    taxAmount: taxAmount,
    totalAmount: totalAmount,
    department: String(line.department || '').trim(),
    jobRef: String(line.jobRef || '').trim(),
    remarks: String(line.remarks || '').trim(),
    receivedQty: 0,
    pendingQty: qty,
    createdAt: now
  };
}

function _purchaseNextVendorCode_() {
  const rows = _purchaseListVendors_();
  const max = rows.reduce((m, v) => {
    const n = Number(String(v.vendorCode || '').replace(/[^0-9]/g, ''));
    return Math.max(m, n || 0);
  }, 0);
  return 'V' + String(max + 1).padStart(5, '0');
}

function _purchaseNextPoNo_() {
  const fy = _fyString_(new Date()).replace('-', '');
  const rows = _purchaseListPOHeaders_();
  const prefix = 'PO/' + fy + '/';
  const max = rows.reduce((m, row) => {
    const poNo = String(row.poNo || '');
    if (poNo.indexOf(prefix) !== 0) return m;
    const n = Number(poNo.slice(prefix.length));
    return Math.max(m, n || 0);
  }, 0);
  return prefix + String(max + 1).padStart(4, '0');
}

function _purchaseItemTaxPct_(item) {
  if (!item) return 0;
  const candidates = [
    item.gst_pct,
    item.gstPercent,
    item.gst_percent,
    item.gst,
    item.gst_rate,
    item.tax_pct,
    item.tax_percent
  ];
  for (let i = 0; i < candidates.length; i++) {
    const n = Number(candidates[i]);
    if (!isNaN(n)) return n;
  }
  return 0;
}

function _purchaseIsoDate_(value) {
  if (!value) return '';
  const dt = new Date(value);
  if (isNaN(dt)) return '';
  return Utilities.formatDate(dt, Session.getScriptTimeZone(), 'yyyy-MM-dd');
}

function _purchaseNowIso_() {
  return new Date().toISOString();
}

function _purchaseNormalizeVendor_(payload, existing) {
  const now = _purchaseNowIso_();
  return {
    id: existing?.id || Utilities.getUuid(),
    vendorCode: String(existing?.vendorCode || _purchaseNextVendorCode_()).trim(),
    vendorName: String(payload.vendorName || '').trim(),
    contactPerson: String(payload.contactPerson || '').trim(),
    email: String(payload.email || '').trim(),
    phone: String(payload.phone || '').trim(),
    gstin: String(payload.gstin || '').trim(),
    address: String(payload.address || '').trim(),
    city: String(payload.city || '').trim(),
    state: String(payload.state || '').trim(),
    category: String(payload.category || '').trim(),
    notes: String(payload.notes || '').trim(),
    isActive: payload.isActive === false ? false : true,
    createdAt: existing?.createdAt || now,
    updatedAt: now
  };
}

function purchaseListVendorsJSON() {
  return {
    ok: true,
    rows: _purchaseListVendors_()
      .slice()
      .sort((a, b) => String(a.vendorName || '').localeCompare(String(b.vendorName || '')))
  };
}

function purchaseSaveVendor(payload) {
  if (!payload) throw new Error('Vendor details are required');

  const required = [
    ['vendorName', 'Vendor name'],
    ['category', 'Vendor category'],
    ['contactPerson', 'Contact person'],
    ['email', 'Email'],
    ['phone', 'Phone'],
    ['address', 'Address'],
    ['city', 'City'],
    ['state', 'State']
  ];

  const missing = required
    .filter(pair => !String(payload[pair[0]] || '').trim())
    .map(pair => pair[1]);

  if (missing.length) {
    throw new Error('Missing required fields: ' + missing.join(', '));
  }

  const existing = _purchaseListVendors_().find(v => v.id === payload.id) || null;
  const record = _purchaseNormalizeVendor_(payload, existing);

  const dbRow = {
    id: record.id,
    vendor_code: record.vendorCode,
    vendor_name: record.vendorName,
    contact_person: record.contactPerson,
    email: record.email,
    phone: record.phone,
    gstin: record.gstin,
    address: record.address,
    city: record.city,
    state: record.state,
    category: record.category,
    notes: record.notes,
    is_active: record.isActive,
    created_at: record.createdAt,
    updated_at: record.updatedAt
  };

  if (existing?.id) {
    supabaseUpdate('purchase_vendors', { id: 'eq.' + existing.id }, dbRow);
  } else {
    supabaseInsert('purchase_vendors', dbRow);
  }
  PropertiesService.getScriptProperties().setProperty('PURCHASE_CACHE_VERSION', String(Date.now()));
  return { ok: true, vendor: record };
}

function purchaseSetVendorStatus(payload) {
  if (!payload || !payload.id) throw new Error('Vendor id is required');
  const existing = _purchaseListVendors_().find(v => v.id === String(payload.id || '').trim());
  if (!existing) throw new Error('Vendor not found');
  const isActive = payload.isActive === false ? false : true;
  supabaseUpdate('purchase_vendors', { id: 'eq.' + existing.id }, {
    is_active: isActive,
    updated_at: _purchaseNowIso_()
  });
  PropertiesService.getScriptProperties().setProperty('PURCHASE_CACHE_VERSION', String(Date.now()));
  return { ok: true, id: existing.id, isActive: isActive };
}

