function purchaseSaveLeadTimeBulk(payload) {
  const rows = Array.isArray(payload) ? payload : (payload && Array.isArray(payload.rows) ? payload.rows : []);
  if (!rows.length) throw new Error('No lead time rows to save.');

  const itemMap = {};
  const itemIds = [...new Set(rows.map(function(row) {
    return String(row && row.id || '').trim();
  }).filter(Boolean))];
  if (!itemIds.length) throw new Error('No inventory items selected for lead time update.');

  try {
    (_supabaseSelectByKeyInBatches_('v_purchase_lead_time_items', 'id,item_code,item_name', 'id', itemIds, null, 40) || []).forEach(function(row) {
      const id = String(row.id || '').trim();
      if (!id) return;
      itemMap[id] = {
        id: id,
        itemCode: String(row.item_code || '').trim(),
        itemName: String(row.item_name || '').trim()
      };
    });
  } catch (err) {}

  if (Object.keys(itemMap).length !== itemIds.length) {
    (_supabaseSelectByKeyInBatches_('inv_items', 'id,item_code,item_name', 'id', itemIds, null, 40) || []).forEach(function(row) {
      const id = String(row.id || '').trim();
      if (!id) return;
      itemMap[id] = {
        id: id,
        itemCode: String(row.item_code || '').trim(),
        itemName: String(row.item_name || '').trim()
      };
    });
  }

  const actor = String((payload && payload.updatedBy) || 'ERP User').trim() || 'ERP User';
  const now = new Date().toISOString();
  let updated = 0;

  rows.forEach(function(row) {
    const id = String(row && row.id || '').trim();
    if (!id) return;
    if (!itemMap[id]) throw new Error('Inventory item not found for lead time update: ' + id);

    const leadTimeRaw = row.leadTimeDays;
    const moqRaw = row.moqQty;
    const leadTimeBlank = leadTimeRaw === '' || leadTimeRaw === null || typeof leadTimeRaw === 'undefined';
    const moqBlank = moqRaw === '' || moqRaw === null || typeof moqRaw === 'undefined';
    const leadTime = leadTimeBlank ? null : Number(leadTimeRaw);
    const moqQty = moqBlank ? null : Number(moqRaw);

    if (!leadTimeBlank && (!isFinite(leadTime) || leadTime < 0)) {
      throw new Error('Lead time must be zero or greater for item ' + (itemMap[id].itemCode || id));
    }
    if (!moqBlank && (!isFinite(moqQty) || moqQty < 0)) {
      throw new Error('MOQ must be zero or greater for item ' + (itemMap[id].itemCode || id));
    }

    supabaseUpdate('inv_items', { id: 'eq.' + id }, {
      lead_time_days: leadTime,
      moq_qty: moqQty,
      lead_time_updated_at: now,
      lead_time_updated_by: actor
    });
    updated++;
  });

  PropertiesService.getScriptProperties().setProperty('PURCHASE_CACHE_VERSION', String(Date.now()));
  return { ok: true, updated: updated, updatedAt: now };
}

function purchaseListInventoryRequestsJSON(opts = {}) {
  const filters = {};
  const purchaseCacheVersion = PropertiesService.getScriptProperties().getProperty('PURCHASE_CACHE_VERSION') || '0';
  const forceRefresh = opts.forceRefresh === true;
  const targetPrNos = Array.isArray(opts.prNos)
    ? [...new Set(opts.prNos.map(function(v) { return String(v || '').trim(); }).filter(Boolean))]
    : [];
  const hasDateFilter = !!(opts.fromDate || opts.toDate);
  const defaultLimit = (opts.pendingOnly === true || String(opts.status || '').trim().toUpperCase() === 'OPEN' || hasDateFilter) ? 50000 : 1000;
  const requestLimit = Math.max(targetPrNos.length || 0, Math.max(1, Number(opts.limit || defaultLimit) || defaultLimit));
  const cacheKey = _cacheKeyHash_('PURCHASE_REQUESTS_OPEN', JSON.stringify({
    v: purchaseCacheVersion,
    status: String(opts.status || ''),
    pendingOnly: opts.pendingOnly === true ? 1 : 0,
    fromDate: String(opts.fromDate || ''),
    toDate: String(opts.toDate || ''),
    prNos: targetPrNos.slice().sort(),
    limit: requestLimit
  }));
  const cache = CacheService.getScriptCache();
  if (!forceRefresh) {
    const cached = cache.get(cacheKey);
    if (cached) {
      try {
        return JSON.parse(cached);
      } catch (err) {
        cache.remove(cacheKey);
      }
    }
  }

  if (opts.status) filters.status = 'eq.' + opts.status;
  if (targetPrNos.length) filters.pr_no = _supabaseInFilter_(targetPrNos);
  if (!opts.pendingOnly && opts.fromDate && opts.toDate) {
    filters.and = `(created_at.gte.${opts.fromDate}T00:00:00,created_at.lte.${opts.toDate}T23:59:59)`;
  } else if (!opts.pendingOnly && opts.fromDate) {
    filters.created_at = `gte.${opts.fromDate}T00:00:00`;
  } else if (!opts.pendingOnly && opts.toDate) {
    filters.created_at = `lte.${opts.toDate}T23:59:59`;
  }

  let viewRows = null;
  if (opts.pendingOnly !== true) {
    try {
      viewRows = _supabaseSelectAll_('v_purchase_requests_open', {
        filters: filters,
        order: 'created_at.desc'
      }, 1000, requestLimit) || [];
    } catch (err) {
      viewRows = null;
    }
  }
  if (viewRows !== null) {
    const itemCodes = [...new Set(viewRows.map(function(r) {
      return String(r.item_code || '').trim();
    }).filter(Boolean))];
    const itemUomMap = {};
    if (itemCodes.length) {
      (_supabaseSelectByKeyInBatches_('inv_items', 'item_code,uom', 'item_code', itemCodes, null, 40) || []).forEach(function(item) {
        itemUomMap[item.item_code] = String(item.uom || '').trim();
      });
    }
    const receiptSeed = {};
    viewRows.forEach(function(r) {
      if (r.pr_no) receiptSeed[r.pr_no] = Number(r.received_qty || 0);
    });
    const activePoLineMap = _purchaseBuildActivePRPoLineMap_(viewRows.map(function(r) {
      return r.pr_no;
    }), receiptSeed);
    const normalized = viewRows.map(function(r) {
      const linked = activePoLineMap[r.pr_no] || { orderedQty: 0, openPOQty: 0, refs: [], latestRate: 0, latestTaxPct: 0 };
      const requestedQty = Number(r.requested_qty || 0);
      const receivedQty = Number(r.received_qty || 0);
      const pendingReceiptQty = Math.max(0, requestedQty - receivedQty);
      return {
        prNo: r.pr_no,
        date: r.created_at,
        itemCode: r.item_code,
        itemName: r.item_name,
        requestedQty: requestedQty,
        receivedQty: receivedQty,
        pendingReceiptQty: pendingReceiptQty,
        orderedQty: Number(linked.orderedQty || 0),
        openPOQty: Number(linked.openPOQty || 0),
        uom: String(r.uom || itemUomMap[r.item_code] || '').trim(),
        poRate: Number(linked.latestRate || 0),
        taxPct: Number(linked.latestTaxPct || r.tax_pct || 0),
        availableToOrderQty: Math.max(0, pendingReceiptQty - Number(linked.openPOQty || 0)),
        department: r.department || '',
        jobRef: r.job_ref || '',
        remarks: r.remarks || '',
        status: r.status || 'OPEN',
        poRefs: linked.refs || []
      };
    });

    const result = {
      ok: true,
      rows: normalized.filter(function(r) {
        return opts.pendingOnly ? Number(r.availableToOrderQty || 0) > 0 : true;
      })
    };
    _putCachedJson_(cacheKey, result, 120);
    return result;
  }

  const rows = supabaseSelect('inv_purchase_requests', {
    select: `
      pr_no,
      created_at,
      item_code,
      item_name,
      requested_qty,
      received_qty,
      department,
      job_ref,
      remarks,
      status
    `,
    filters,
    order: 'created_at.desc',
    limit: requestLimit
  }) || [];

  const itemCodes = [...new Set(rows.map(r => r.item_code).filter(Boolean))];
  const itemTaxMap = {};
  const itemUomMap = {};
  if (itemCodes.length) {
    (_supabaseSelectByKeyInBatches_('inv_items', '*', 'item_code', itemCodes, null, 40) || []).forEach(item => {
      itemTaxMap[item.item_code] = _purchaseItemTaxPct_(item);
      itemUomMap[item.item_code] = String(item.uom || item.unit || '').trim();
    });
  }

  const prReceiptMap = {};
  rows.forEach(r => {
    prReceiptMap[r.pr_no] = Number(r.received_qty || 0);
  });

  const poLineMap = _purchaseBuildActivePRPoLineMap_(rows.map(function(r) { return r.pr_no; }), prReceiptMap);

  const normalized = rows.map(r => {
      const linked = poLineMap[r.pr_no] || { orderedQty: 0, openPOQty: 0, refs: [], latestRate: 0 };
      const requestedQty = Number(r.requested_qty || 0);
      const receivedQty = Number(r.received_qty || 0);
      const pendingReceiptQty = Math.max(0, requestedQty - receivedQty);
      const orderedQty = Number(linked.orderedQty || 0);
      const openPOQty = Number(linked.openPOQty || 0);
      return {
        prNo: r.pr_no,
        date: r.created_at,
        itemCode: r.item_code,
        itemName: r.item_name,
        requestedQty: requestedQty,
        receivedQty: receivedQty,
        pendingReceiptQty: pendingReceiptQty,
        orderedQty: orderedQty,
        openPOQty: openPOQty,
        uom: String(itemUomMap[r.item_code] || '').trim(),
        poRate: Number(linked.latestRate || 0),
        taxPct: Number(itemTaxMap[r.item_code] || 0),
        availableToOrderQty: Math.max(0, pendingReceiptQty - openPOQty),
        department: r.department || '',
        jobRef: r.job_ref || '',
        remarks: r.remarks || '',
        status: r.status || 'OPEN',
        poRefs: linked.refs || []
      };
    });

  const result = {
    ok: true,
    rows: normalized.filter(r => opts.pendingOnly ? Number(r.availableToOrderQty || 0) > 0 : true)
  };

  _putCachedJson_(cacheKey, result, 120);
  return result;
}

function purchaseListPOsJSON(opts = {}) {
  const forceRefresh = opts.forceRefresh === true;
  const includeOpenOutsideDate = opts.includeOpenOutsideDate === true || opts.pendingOnly === true;
  const purchaseCacheVersion = PropertiesService.getScriptProperties().getProperty('PURCHASE_CACHE_VERSION') || '0';
  const cacheKey = _reportsCacheKey_('PURCHASE_LIST_POS', { v: purchaseCacheVersion, logic: 'receipt-row-first-v4-line-id', opts: opts || {}, includeOpenOutsideDate: includeOpenOutsideDate ? 1 : 0 });
  if (!forceRefresh) {
    const cached = _getCachedJson_(cacheKey);
    if (cached) return cached;
  }

  const receiptRows = (opts.poNo && forceRefresh)
    ? _purchaseReceiptRowsForPO_(opts.poNo)
    : _purchaseListPOReceipts_();
  const receiptEntriesByLine = {};
  receiptRows.forEach(function(row) {
    const lineId = String(row.poLineId || '').trim();
    if (!lineId) return;
    if (!receiptEntriesByLine[lineId]) receiptEntriesByLine[lineId] = [];
    receiptEntriesByLine[lineId].push(row);
  });

  const linesForLedgerFallback = opts.poNo ? _purchaseListPOLinesForPO_(opts.poNo) : _purchaseListPOLines_();
  const ledgerReceiptEntriesByLine = _purchaseLedgerPOReceiptEntriesByLine_(linesForLedgerFallback);

  let viewRows = null;
  if (!forceRefresh) {
    try {
      const viewFilters = {};
      if (opts.poNo) viewFilters.po_no = 'eq.' + String(opts.poNo || '').trim();
      viewRows = _supabaseSelectAll_('v_purchase_orders_read_model', {
        filters: viewFilters,
        order: 'order_date.desc,created_at.desc,line_no.asc'
      }, 1000, 50000) || [];
    } catch (err) {
      viewRows = null;
    }
  }
  if (viewRows !== null) {
    const grouped = {};
    viewRows.forEach(function(row) {
      const poNo = row.po_no || '';
      if (!poNo) return;
      if (!grouped[poNo]) {
        grouped[poNo] = {
          poNo: poNo,
          orderDate: row.order_date || '',
          vendorId: row.vendor_id || '',
          vendorName: row.vendor_name || '',
          vendorGstin: row.vendor_gstin || '',
          status: row.status || 'OPEN',
          storedStatus: row.status || 'OPEN',
          lineCount: 0,
          totalQty: 0,
          receivedQty: 0,
          pendingQty: 0,
          basicTotal: 0,
          taxTotal: 0,
          totalValue: 0,
          storedTotalValue: Number(row.total_value || 0),
          buyerName: row.created_by || '',
          paymentTerms: row.payment_terms || '',
          freightTerms: row.freight_terms || '',
          freightValue: Number(row.freight_value || 0),
          deliveryTerms: row.delivery_terms || '',
          notes: row.notes || '',
          workflow: '',
          artworkType: '',
          lines: []
        };
      }
      const group = grouped[poNo];
      const inlineEntries = Array.isArray(row.receipt_entries) ? row.receipt_entries : [];
      const rowLineId = String(row.line_id || '').trim();
      const linkedEntries = receiptEntriesByLine[rowLineId] || [];
      const fallbackEntries = ledgerReceiptEntriesByLine[rowLineId] || [];
      const liveEntries = (linkedEntries.length ? linkedEntries : fallbackEntries)
        .slice()
        .sort(function(a, b) {
          return String(b.receiptDate || '').localeCompare(String(a.receiptDate || '')) ||
            String(b.createdAt || '').localeCompare(String(a.createdAt || ''));
        });
      const liveReceived = liveEntries.reduce(function(sum, entry) {
        return sum + Number(entry.qty || 0);
      }, 0);
      const derivedReceived = liveReceived;
      const baseLineForClose = {
        qty: Number(row.qty || 0),
        remarks: row.remarks || ''
      };
      const shortClosedQty = _purchasePOLineShortClosedQty_(baseLineForClose, derivedReceived);
      const pendingQty = Math.max(0, Number(row.qty || 0) - derivedReceived - shortClosedQty);
      const line = {
        id: row.line_id,
        poId: row.po_id,
        poNo: row.po_no,
        lineNo: Number(row.line_no || 0),
        sourceType: row.source_type || '',
        sourceRef: row.source_ref || '',
        itemCode: row.item_code || '',
        itemName: row.item_name || '',
        qty: Number(row.qty || 0),
        rate: Number(row.rate || 0),
        taxPct: Number(row.tax_pct || 0),
        amount: Number(row.amount || 0),
        taxAmount: Number(row.tax_amount || 0),
        totalAmount: Number(row.total_amount || 0),
        department: row.department || '',
        jobRef: row.job_ref || '',
        remarks: row.remarks || '',
        createdAt: row.line_created_at || '',
        receivedQty: derivedReceived,
        pendingQty: pendingQty,
        shortClosedQty: shortClosedQty,
        isShortClosed: shortClosedQty > 0,
        overReceivedQty: Math.max(0, derivedReceived - Number(row.qty || 0)),
        receiptEntries: liveEntries.length ? liveEntries : []
      };
      group.lines.push(line);
      group.lineCount += 1;
      group.totalQty += Number(row.qty || 0);
      group.receivedQty += Number(line.receivedQty || 0);
      group.pendingQty += Number(line.pendingQty || 0);
      group.shortClosedQty = Number(group.shortClosedQty || 0) + Number(line.shortClosedQty || 0);
      group.basicTotal += Number(row.amount || 0);
      group.taxTotal += Number(row.tax_amount || 0);
      group.totalValue += Number(row.total_amount || 0);
      if (!group.workflow) {
        const isArtworkPO = _purchaseIsPlateDieSource_(line.sourceType);
        const hasDieLines = _purchasePlateDieTypeFromSource_(line.sourceType) === 'DIE';
        const hasPlateLines = _purchasePlateDieTypeFromSource_(line.sourceType) === 'PLATE';
        group.workflow = isArtworkPO ? 'ARTWORK_PROCUREMENT' : 'INVENTORY_PR';
        group.artworkType = hasDieLines ? (hasPlateLines ? 'MIXED' : 'DIE') : (isArtworkPO ? 'PLATE' : 'INVENTORY');
      }
    });

    const rows = Object.keys(grouped)
      .map(function(poNo) {
        const row = grouped[poNo];
        if (_purchaseIsCancelledStatus_(row.storedStatus)) {
          row.status = 'CANCELLED';
          row.pendingQty = 0;
          row.lines = (row.lines || []).map(function(line) {
            return Object.assign({}, line, { pendingQty: 0 });
          });
        } else {
          row.status = _purchaseDerivePOStatusWithShortClose_(row.totalQty, row.receivedQty, row.shortClosedQty || 0);
          row.pendingQty = Math.max(0, row.totalQty - row.receivedQty - Number(row.shortClosedQty || 0));
        }
        row.totalValue = Number(row.storedTotalValue || 0) || (row.totalValue + Number(row.freightValue || 0));
        return row;
      })
      .filter(function(row) {
        if (opts.poNo && String(row.poNo || '') !== String(opts.poNo || '').trim()) return false;
        if (opts.pendingOnly) return !_purchaseIsCancelledStatus_(row.status) && Number(row.pendingQty || 0) > 0;
        const isOpenOrPending = !_purchaseIsCancelledStatus_(row.status) && Number(row.pendingQty || 0) > 0;
        if (includeOpenOutsideDate && isOpenOrPending) return true;
        const rowDate = row.orderDate ? new Date(row.orderDate) : null;
        if (opts.fromDate && rowDate && rowDate < new Date(opts.fromDate + 'T00:00:00')) return false;
        if (opts.toDate && rowDate && rowDate > new Date(opts.toDate + 'T23:59:59')) return false;
        return true;
      })
      .sort(function(a, b) {
        return String(b.orderDate || '').localeCompare(String(a.orderDate || ''));
      });
    if (opts.limit) rows.splice(Number(opts.limit || rows.length));

    const result = { ok: true, rows: rows };
    _putCachedJson_(cacheKey, result, 120);
    return result;
  }

  const headers = opts.poNo
    ? (function() {
        const header = _purchaseGetPOHeaderByNo_(opts.poNo);
        return header ? [header] : [];
      })()
    : _purchaseListPOHeaders_();
  const linesAll = linesForLedgerFallback;
  const vendors = {};
  _purchaseListVendors_().forEach(v => { vendors[v.id] = v; });
  const rows = headers
    .slice()
    .sort((a, b) => String(b.orderDate || '').localeCompare(String(a.orderDate || '')))
    .map(header => {
      const lines = linesAll
        .filter(line => line.poNo === header.poNo)
        .sort((a, b) => Number(a.lineNo || 0) - Number(b.lineNo || 0));

      const normalizedLines = lines.map(line => {
        const linkedEntries = receiptEntriesByLine[line.id] || [];
        const fallbackEntries = ledgerReceiptEntriesByLine[line.id] || [];
        const lineReceiptEntries = linkedEntries.length ? linkedEntries : fallbackEntries;
        const liveReceived = lineReceiptEntries.reduce((sum, row) => sum + Number(row.qty || 0), 0);
        const derivedReceived = liveReceived;
        const shortClosedQty = _purchasePOLineShortClosedQty_(line, derivedReceived);
        const pendingQty = Math.max(0, Number(line.qty || 0) - derivedReceived - shortClosedQty);
        return Object.assign({}, line, {
          receivedQty: derivedReceived,
          pendingQty: pendingQty,
          shortClosedQty: shortClosedQty,
          isShortClosed: shortClosedQty > 0,
          overReceivedQty: Math.max(0, derivedReceived - Number(line.qty || 0)),
          receiptEntries: lineReceiptEntries.slice().sort((a, b) => String(b.receiptDate || '').localeCompare(String(a.receiptDate || '')) || String(b.createdAt || '').localeCompare(String(a.createdAt || '')))
        });
      });

      const totalQty = normalizedLines.reduce((sum, line) => sum + Number(line.qty || 0), 0);
      const basicTotal = normalizedLines.reduce((sum, line) => sum + Number(line.amount || 0), 0);
      const taxTotal = normalizedLines.reduce((sum, line) => sum + Number(line.taxAmount || 0), 0);
      const freightValue = Number(header.freightValue || 0);
      const vendor = vendors[header.vendorId] || {};
      const freightTax = _purchaseFreightTaxBreakup_(vendor.state, freightValue);
      const totalValue = normalizedLines.reduce((sum, line) => sum + Number(line.totalAmount || line.amount || 0), 0) + freightValue + freightTax.taxAmount;
      const receivedQty = normalizedLines.reduce((sum, line) => sum + Number(line.receivedQty || 0), 0);
      const shortClosedQty = normalizedLines.reduce((sum, line) => sum + Number(line.shortClosedQty || 0), 0);
      const pendingQty = Math.max(0, totalQty - receivedQty - shortClosedQty);
      const liveStatus = _purchaseIsCancelledStatus_(header.status)
        ? 'CANCELLED'
        : _purchaseDerivePOStatusWithShortClose_(totalQty, receivedQty, shortClosedQty);
      const isArtworkPO = normalizedLines.some(line => _purchaseIsPlateDieSource_(line.sourceType));
      const hasDieLines = normalizedLines.some(line => _purchasePlateDieTypeFromSource_(line.sourceType) === 'DIE');
      const hasPlateLines = normalizedLines.some(line => _purchasePlateDieTypeFromSource_(line.sourceType) === 'PLATE');
      const artworkType = hasDieLines
        ? (hasPlateLines ? 'MIXED' : 'DIE')
        : (isArtworkPO ? 'PLATE' : 'INVENTORY');

      return {
        poNo: header.poNo,
        orderDate: header.orderDate,
        vendorId: header.vendorId || '',
        vendorName: header.vendorName || vendor.vendorName || '',
        vendorGstin: vendor.gstin || '',
        status: liveStatus,
        storedStatus: header.status || 'OPEN',
        lineCount: lines.length,
        totalQty: totalQty,
        receivedQty: receivedQty,
        pendingQty: _purchaseIsCancelledStatus_(header.status) ? 0 : pendingQty,
        shortClosedQty: shortClosedQty,
        basicTotal: basicTotal,
        taxTotal: taxTotal + freightTax.taxAmount,
        totalValue: totalValue,
        buyerName: header.createdBy || '',
        paymentTerms: header.paymentTerms || '',
        freightTerms: header.freightTerms || '',
        freightValue: freightValue,
        deliveryTerms: header.deliveryTerms || '',
        notes: header.notes || '',
        workflow: isArtworkPO ? 'ARTWORK_PROCUREMENT' : 'INVENTORY_PR',
        artworkType: artworkType,
        lines: _purchaseIsCancelledStatus_(header.status)
          ? normalizedLines.map(function(line) { return Object.assign({}, line, { pendingQty: 0 }); })
          : normalizedLines
      };
    })
    .filter(row => {
      if (opts.pendingOnly) return !_purchaseIsCancelledStatus_(row.status) && Number(row.pendingQty || 0) > 0;
      const isOpenOrPending = !_purchaseIsCancelledStatus_(row.status) && Number(row.pendingQty || 0) > 0;
      if (includeOpenOutsideDate && isOpenOrPending) return true;
      const rowDate = row.orderDate ? new Date(row.orderDate) : null;
      if (opts.fromDate && rowDate && rowDate < new Date(opts.fromDate + 'T00:00:00')) return false;
      if (opts.toDate && rowDate && rowDate > new Date(opts.toDate + 'T23:59:59')) return false;
      return true;
    });
  if (opts.limit) rows.splice(Number(opts.limit || rows.length));

  const result = { ok: true, rows: rows };
  _putCachedJson_(cacheKey, result, 120);
  return result;
}

function _purchaseNormalizePOSummaryRow_(row) {
  const status = row.status || 'OPEN';
  const cancelled = _purchaseIsCancelledStatus_(status);
  return {
    poNo: row.po_no || row.poNo || '',
    poId: row.po_id || row.poId || '',
    orderDate: row.order_date || row.orderDate || '',
    vendorId: row.vendor_id || row.vendorId || '',
    vendorName: row.vendor_name || row.vendorName || '',
    vendorGstin: row.vendor_gstin || row.vendorGstin || '',
    status: cancelled ? 'CANCELLED' : status,
    storedStatus: row.status || row.storedStatus || 'OPEN',
    lineCount: Number(row.line_count || row.lineCount || 0),
    totalQty: Number(row.total_qty || row.totalQty || 0),
    receivedQty: Number(row.received_qty || row.receivedQty || 0),
    pendingQty: cancelled ? 0 : Number(row.pending_qty || row.pendingQty || 0),
    basicTotal: Number(row.basic_total || row.basicTotal || 0),
    taxTotal: Number(row.tax_total || row.taxTotal || 0),
    totalValue: Number(row.total_value || row.totalValue || 0),
    buyerName: row.created_by || row.buyerName || '',
    paymentTerms: row.payment_terms || row.paymentTerms || '',
    freightTerms: row.freight_terms || row.freightTerms || '',
    freightValue: Number(row.freight_value || row.freightValue || 0),
    deliveryTerms: row.delivery_terms || row.deliveryTerms || '',
    notes: row.notes || '',
    workflow: row.workflow || '',
    artworkType: row.artwork_type || row.artworkType || ''
  };
}

function purchaseListPOSummariesJSON(opts = {}) {
  const forceRefresh = opts.forceRefresh === true;
  const purchaseCacheVersion = PropertiesService.getScriptProperties().getProperty('PURCHASE_CACHE_VERSION') || '0';
  const cacheKey = _reportsCacheKey_('PURCHASE_LIST_PO_SUMMARIES', { v: purchaseCacheVersion, opts: opts || {} });
  if (!forceRefresh) {
    const cached = _getCachedJson_(cacheKey);
    if (cached) return cached;
  }

  let viewRows = null;
  try {
    const filters = {};
    if (opts.poNo) filters.po_no = 'eq.' + String(opts.poNo || '').trim();
    viewRows = _supabaseSelectAll_('v_purchase_order_summary', {
      filters: filters,
      order: 'order_date.desc,updated_at.desc,po_no.desc'
    }, 1000, 50000) || [];
  } catch (err) {
    viewRows = null;
  }

  if (viewRows !== null) {
    const rows = viewRows
      .map(_purchaseNormalizePOSummaryRow_)
      .filter(function(row) {
        if (opts.poNo && String(row.poNo || '') !== String(opts.poNo || '').trim()) return false;
        if (opts.pendingOnly) return !_purchaseIsCancelledStatus_(row.status) && Number(row.pendingQty || 0) > 0;
        const rowDate = row.orderDate ? new Date(row.orderDate) : null;
        if (opts.fromDate && rowDate && rowDate < new Date(opts.fromDate + 'T00:00:00')) return false;
        if (opts.toDate && rowDate && rowDate > new Date(opts.toDate + 'T23:59:59')) return false;
        return true;
      })
      .sort(function(a, b) {
        const dateCompare = String(b.orderDate || '').localeCompare(String(a.orderDate || ''));
        if (dateCompare !== 0) return dateCompare;
        return String(b.poNo || '').localeCompare(String(a.poNo || ''));
      });
    if (opts.limit) rows.splice(Number(opts.limit || rows.length));
    const result = { ok: true, rows: rows };
    _putCachedJson_(cacheKey, result, 120);
    return result;
  }

  const fallbackRows = (purchaseListPOsJSON(opts).rows || []).map(function(row) {
    return _purchaseNormalizePOSummaryRow_(row);
  });
  const result = { ok: true, rows: fallbackRows };
  _putCachedJson_(cacheKey, result, 120);
  return result;
}

function purchaseGetPODetail(poNo, opts) {
  const key = String(poNo || '').trim();
  if (!key) throw new Error('PO number is required');
  const forceRefresh = opts?.forceRefresh === true;
  const purchaseCacheVersion = PropertiesService.getScriptProperties().getProperty('PURCHASE_CACHE_VERSION') || '0';
  const cacheKey = _reportsCacheKey_('PURCHASE_PO_DETAIL', { v: purchaseCacheVersion, poNo: key });
  if (!forceRefresh) {
    const cached = _getCachedJson_(cacheKey);
    if (cached) return cached;
  }
  const rows = purchaseListPOsJSON({ poNo: key, limit: 1, forceRefresh: forceRefresh }).rows || [];
  const row = rows.find(function(item) {
    return String(item.poNo || '') === key;
  }) || null;
  if (!row) throw new Error('Purchase order not found: ' + key);
  const result = { ok: true, row: row };
  _putCachedJson_(cacheKey, result, 120);
  return result;
}

function purchaseListPOsForPRJSON(prNo) {
  const refNo = String(prNo || '').trim();
  if (!refNo) {
    throw new Error('PR No is required');
  }

  const baseLines = (supabaseSelect('purchase_order_lines', {
    filters: { source_ref: 'eq.' + refNo },
    order: 'po_no.asc,line_no.asc'
  }) || []);

  if (!baseLines.length) {
    return { ok: true, rows: [] };
  }

  const poIds = [...new Set(baseLines.map(line => line.po_id).filter(Boolean))];
  const lines = (supabaseSelect('purchase_order_lines', {
    filters: { po_id: _supabaseInFilter_(poIds) },
    order: 'po_no.asc,line_no.asc'
  }) || []).map(l => ({
    id: l.id,
    poId: l.po_id,
    poNo: l.po_no,
    lineNo: Number(l.line_no || 0),
    sourceType: l.source_type || '',
    sourceRef: l.source_ref || '',
    itemCode: l.item_code || '',
    itemName: l.item_name || '',
    qty: Number(l.qty || 0),
    rate: Number(l.rate || 0),
    taxPct: Number(l.tax_pct || 0),
    amount: Number(l.amount || 0),
    taxAmount: Number(l.tax_amount || 0),
    totalAmount: Number(l.total_amount || l.amount || 0),
    department: l.department || '',
    jobRef: l.job_ref || '',
    remarks: l.remarks || '',
    createdAt: l.created_at || ''
  }));
  const headers = [];
  for (let i = 0; i < poIds.length; i += 10) {
    const chunk = poIds.slice(i, i + 10);
    headers.push.apply(headers, (supabaseSelect('purchase_orders', {
      filters: { id: 'in.(' + chunk.join(',') + ')' },
      order: 'order_date.desc,created_at.desc'
    }) || []).map(h => ({
      id: h.id,
      poNo: h.po_no,
      orderDate: h.order_date,
      vendorId: h.vendor_id,
      vendorName: h.vendor_name || '',
      paymentTerms: h.payment_terms || '',
      freightTerms: h.freight_terms || '',
      freightValue: Number(h.freight_value || 0),
      deliveryTerms: h.delivery_terms || '',
      notes: h.notes || '',
      status: h.status || 'OPEN',
      createdBy: h.created_by || ''
    })));
  }

  const vendorIds = [...new Set(headers.map(function(header) {
    return header.vendorId;
  }).filter(Boolean))];
  const vendorMap = {};
  for (let i = 0; i < vendorIds.length; i += 20) {
    const chunk = vendorIds.slice(i, i + 20);
    (supabaseSelect('purchase_vendors', {
      select: 'id,gstin',
      filters: { id: _supabaseInFilter_(chunk) }
    }) || []).forEach(function(vendor) {
      vendorMap[String(vendor.id || '')] = {
        gstin: String(vendor.gstin || '').trim()
      };
    });
  }

  const headerMap = {};
  headers.forEach(header => {
    if (header.id) {
      header.vendorGstin = vendorMap[String(header.vendorId || '')]?.gstin || '';
      headerMap[header.id] = header;
    }
  });

  const receiptEntriesByLine = {};
  _purchaseListPOReceipts_().forEach(function(row) {
    const lineId = String(row.poLineId || '').trim();
    if (!lineId) return;
    if (!receiptEntriesByLine[lineId]) receiptEntriesByLine[lineId] = [];
    receiptEntriesByLine[lineId].push(row);
  });
  const ledgerReceiptEntriesByLine = _purchaseLedgerPOReceiptEntriesByLine_(lines);

  const grouped = {};
  lines.forEach(line => {
    const header = headerMap[line.poId] || {};
    const poKey = line.poNo || header.poNo || '';
    if (!poKey) return;
    if (!grouped[poKey]) {
      grouped[poKey] = {
        poNo: poKey,
        orderDate: header.orderDate || '',
        vendorId: header.vendorId || '',
        vendorName: header.vendorName || '',
        vendorGstin: header.vendorGstin || '',
        status: header.status || 'OPEN',
        buyerName: header.createdBy || '',
        paymentTerms: header.paymentTerms || '',
        freightTerms: header.freightTerms || '',
        freightValue: Number(header.freightValue || 0),
        deliveryTerms: header.deliveryTerms || '',
        notes: header.notes || '',
        lines: []
      };
    }

    const lineId = String(line.id || '').trim();
    const linkedEntries = receiptEntriesByLine[lineId] || [];
    const fallbackEntries = ledgerReceiptEntriesByLine[lineId] || [];
    const receiptEntries = linkedEntries.length ? linkedEntries : fallbackEntries;
    const derivedReceived = receiptEntries.reduce(function(sum, row) {
      return sum + Number(row.qty || 0);
    }, 0);
    const shortClosedQty = _purchasePOLineShortClosedQty_(line, derivedReceived);
    grouped[poKey].lines.push(Object.assign({}, line, {
      receivedQty: derivedReceived,
      pendingQty: Math.max(0, Number(line.qty || 0) - derivedReceived - shortClosedQty),
      shortClosedQty: shortClosedQty,
      isShortClosed: shortClosedQty > 0,
      receiptEntries: receiptEntries
    }));
  });

  const rows = Object.keys(grouped)
    .map(poNo => {
      const row = grouped[poNo];
      const totalQty = row.lines.reduce((sum, line) => sum + Number(line.qty || 0), 0);
      const receivedQty = row.lines.reduce((sum, line) => sum + Number(line.receivedQty || 0), 0);
      const shortClosedQty = row.lines.reduce((sum, line) => sum + Number(line.shortClosedQty || 0), 0);
      const basicTotal = row.lines.reduce((sum, line) => sum + Number(line.amount || 0), 0);
      const taxTotal = row.lines.reduce((sum, line) => sum + Number(line.taxAmount || 0), 0);
      const totalValue = row.lines.reduce((sum, line) => sum + Number(line.totalAmount || line.amount || 0), 0) + Number(row.freightValue || 0);
      const liveStatus = _purchaseIsCancelledStatus_(row.status)
        ? 'CANCELLED'
        : _purchaseDerivePOStatusWithShortClose_(totalQty, receivedQty, shortClosedQty);
      return Object.assign(row, {
        status: liveStatus,
        lineCount: row.lines.length,
        totalQty: totalQty,
        receivedQty: receivedQty,
        pendingQty: _purchaseIsCancelledStatus_(row.status) ? 0 : Math.max(0, totalQty - receivedQty - shortClosedQty),
        shortClosedQty: shortClosedQty,
        basicTotal: basicTotal,
        taxTotal: taxTotal,
        totalValue: totalValue
      });
    })
    .sort((a, b) => String(b.orderDate || '').localeCompare(String(a.orderDate || '')));

  return { ok: true, rows: rows };
}

function purchaseCreatePO(payload) {
  if (!payload || !payload.vendorId) {
    throw new Error('Vendor is required');
  }

  const selectedRows = Array.isArray(payload.lines) ? payload.lines : [];
  if (!selectedRows.length) {
    throw new Error('Add at least one PO line');
  }
  if (selectedRows.some(function(line) {
    const sourceType = String(line && line.sourceType || '').trim().toUpperCase();
    return sourceType !== 'INVENTORY_PR' || !String(line && (line.prNo || line.sourceRef) || '').trim();
  })) {
    throw new Error('Inventory purchase orders can only be created against purchase requests.');
  }

  const vendor = _purchaseListVendors_().find(v => v.id === payload.vendorId);
  if (!vendor) throw new Error('Vendor not found');

  const prNos = [...new Set(selectedRows.map(function(line) {
    return String(line && (line.prNo || line.sourceRef) || '').trim();
  }).filter(Boolean))];
  const prMap = _purchaseGetInventoryPRValidationMap_(prNos);
  const requestedQtyByPr = {};
  selectedRows.forEach(function(line) {
    const prNo = String(line && (line.prNo || line.sourceRef) || '').trim();
    if (!prNo) return;
    requestedQtyByPr[prNo] = Number(requestedQtyByPr[prNo] || 0) + Number(line.qty || 0);
  });
  Object.keys(requestedQtyByPr).forEach(function(prNo) {
    const pr = prMap[prNo];
    if (!pr) throw new Error('PR not found: ' + prNo);
    _purchaseAssertPRCanGeneratePO_(pr, requestedQtyByPr[prNo], {});
  });

  const poNo = _purchaseNextPoNo_();
  const now = _purchaseNowIso_();
  const freightValue = Math.max(0, Number(payload.freightValue || 0));

  const lines = selectedRows.map((line, idx) => {
    if (line && (line.prNo || String(line.sourceType || '').toUpperCase() === 'INVENTORY_PR')) {
      const prNo = String(line.prNo || line.sourceRef || '').trim();
      const pr = prMap[prNo];
      if (!pr) throw new Error('PR not found: ' + prNo);
      return _purchaseNormalizeInventoryPRLine_(line, pr, idx + 1, poNo, now, {
        createdAt: now
      });
    }
    throw new Error('Inventory purchase orders can only be created against purchase requests.');
  });

  const basicTotal = lines.reduce((sum, line) => sum + Number(line.amount || 0), 0);
  const lineTaxTotal = lines.reduce((sum, line) => sum + Number(line.taxAmount || 0), 0);
  const freightTax = _purchaseFreightTaxBreakup_(vendor.state, freightValue);
  const taxTotal = lineTaxTotal + freightTax.taxAmount;
  const totalValue = lines.reduce((sum, line) => sum + Number(line.totalAmount || 0), 0) + freightValue + freightTax.taxAmount;
  const totalQty = lines.reduce((sum, line) => sum + Number(line.qty || 0), 0);

  const headerId = Utilities.getUuid();

  try {
    supabaseInsert('purchase_orders', {
      id: headerId,
      po_no: poNo,
      order_date: payload.orderDate || _purchaseIsoDate_(new Date()),
      vendor_id: vendor.id,
      vendor_name: vendor.vendorName,
      vendor_email: vendor.email || '',
      vendor_phone: vendor.phone || '',
      vendor_address: vendor.address || '',
      payment_terms: String(payload.paymentTerms || '').trim(),
      freight_terms: String(payload.freightTerms || '').trim(),
      freight_value: freightValue,
      delivery_terms: String(payload.deliveryTerms || '').trim(),
      notes: String(payload.notes || '').trim(),
      status: 'OPEN',
      total_qty: totalQty,
      basic_total: basicTotal,
      tax_total: taxTotal,
      total_value: totalValue,
      created_by: String(payload.createdBy || '').trim(),
      created_at: now,
      updated_at: now
    });
  } catch (e) {
    throw new Error('Run purchase_freight_value_schema.sql in Supabase before creating freight-valued purchase orders.');
  }

  supabaseBulkInsert('purchase_order_lines', lines.map(line => ({
    id: line.id,
    po_id: headerId,
    po_no: line.poNo,
    line_no: line.lineNo,
    source_type: line.sourceType,
    source_ref: line.sourceRef,
    item_code: line.itemCode,
    item_name: line.itemName,
    qty: line.qty,
    rate: line.rate,
    tax_pct: line.taxPct,
    amount: line.amount,
    tax_amount: line.taxAmount,
    total_amount: line.totalAmount,
    department: line.department,
    job_ref: line.jobRef,
    remarks: line.remarks,
    created_at: line.createdAt
  })));

  PropertiesService.getScriptProperties().setProperty('PURCHASE_CACHE_VERSION', String(Date.now()));
  return { ok: true, poNo: poNo };
}

function purchaseCreateArtworkPO(payload) {
  if (!payload || !payload.vendorId) throw new Error('Vendor is required');
  const type = String(payload.type || '').trim().toUpperCase();
  if (type !== 'PLATE' && type !== 'DIE') throw new Error('Plate or die type is required');

  const selectedRows = Array.isArray(payload.lines) ? payload.lines : [];
  if (!selectedRows.length) throw new Error('Add at least one PO line');

  const vendor = _purchaseListVendors_().find(v => v.id === payload.vendorId);
  if (!vendor) throw new Error('Vendor not found');

  const artworkRows = {};
  const selectedArtworkKeys = selectedRows.map(function(line) {
    return String(line && line.artworkKey || '').trim();
  }).filter(Boolean);
  if (selectedArtworkKeys.length) {
    getPlateDieJobs({ type: type, artworkKeys: selectedArtworkKeys }).forEach(row => {
      artworkRows[row.artworkKey] = row;
    });
  }

  const poNo = _purchaseNextPoNo_();
  const now = _purchaseNowIso_();
  const headerId = Utilities.getUuid();
  const freightValue = Math.max(0, Number(payload.freightValue || 0));

  const lines = selectedRows.map((line, idx) => {
    const artworkKey = String(line.artworkKey || '').trim();
    if (artworkKey) {
      const base = artworkRows[artworkKey];
      if (!base) throw new Error('Artwork not found for release: ' + artworkKey);

      const qty = Number(line.qty || 0);
      const rate = Number(line.rate || 0);
      const taxPct = Number(line.taxPct || 0);
      if (qty <= 0) throw new Error('Invalid PO qty for artwork ' + (base.artworkNo || artworkKey));
      if (rate <= 0) throw new Error('Invalid PO rate for artwork ' + (base.artworkNo || artworkKey));
      if (taxPct < 0) throw new Error('Invalid tax % for artwork ' + (base.artworkNo || artworkKey));

      const basicAmount = Number((qty * rate).toFixed(2));
      const taxAmount = Number((basicAmount * taxPct / 100).toFixed(2));
      const totalAmount = Number((basicAmount + taxAmount).toFixed(2));
      const artworkLabel = String(base.artworkNo || artworkKey || '').trim();
      const itemName = type + ' - ' + (artworkLabel || 'Artwork');
      const refSummary = (base.memberRefs || []).map(r => [r.soNo, r.lineNo].filter(Boolean).join('/')).filter(Boolean).join(', ');

      return {
        id: Utilities.getUuid(),
        poNo: poNo,
        lineNo: idx + 1,
        sourceType: 'ARTWORK_' + type,
        sourceRef: artworkKey,
        itemCode: artworkLabel || artworkKey,
        itemName: itemName,
        qty: qty,
        rate: rate,
        taxPct: taxPct,
        amount: basicAmount,
        taxAmount: taxAmount,
        totalAmount: totalAmount,
        department: 'PREPRESS',
        jobRef: refSummary || artworkLabel,
        remarks: String(line.remarks || '').trim(),
        receivedQty: 0,
        pendingQty: qty,
        createdAt: now
      };
    }
    if (!String(line.sourceRef || '').trim() || !String(line.jobRef || '').trim()) {
      throw new Error('Artwork Ref and SO / Job Ref are required for direct ' + type.toLowerCase() + ' PO line ' + (idx + 1));
    }
    return _purchaseNormalizeDirectLine_(line, 'DIRECT_' + type, idx + 1, poNo, now);
  });

  const basicTotal = lines.reduce((sum, line) => sum + Number(line.amount || 0), 0);
  const lineTaxTotal = lines.reduce((sum, line) => sum + Number(line.taxAmount || 0), 0);
  const freightTax = _purchaseFreightTaxBreakup_(vendor.state, freightValue);
  const taxTotal = lineTaxTotal + freightTax.taxAmount;
  const totalValue = lines.reduce((sum, line) => sum + Number(line.totalAmount || 0), 0) + freightValue + freightTax.taxAmount;
  const totalQty = lines.reduce((sum, line) => sum + Number(line.qty || 0), 0);

  try {
    supabaseInsert('purchase_orders', {
      id: headerId,
      po_no: poNo,
      order_date: payload.orderDate || _purchaseIsoDate_(new Date()),
      vendor_id: vendor.id,
      vendor_name: vendor.vendorName,
      vendor_email: vendor.email || '',
      vendor_phone: vendor.phone || '',
      vendor_address: vendor.address || '',
      payment_terms: String(payload.paymentTerms || '').trim(),
      freight_terms: String(payload.freightTerms || '').trim(),
      freight_value: freightValue,
      delivery_terms: String(payload.deliveryTerms || '').trim(),
      notes: String(payload.notes || '').trim(),
      status: 'OPEN',
      total_qty: totalQty,
      basic_total: basicTotal,
      tax_total: taxTotal,
      total_value: totalValue,
      created_by: String(payload.createdBy || '').trim(),
      created_at: now,
      updated_at: now
    });
  } catch (e) {
    throw new Error('Run purchase_freight_value_schema.sql in Supabase before creating freight-valued purchase orders.');
  }

  supabaseBulkInsert('purchase_order_lines', lines.map(line => ({
    id: line.id,
    po_id: headerId,
    po_no: line.poNo,
    line_no: line.lineNo,
    source_type: line.sourceType,
    source_ref: line.sourceRef,
    item_code: line.itemCode,
    item_name: line.itemName,
    qty: line.qty,
    rate: line.rate,
    tax_pct: line.taxPct,
    amount: line.amount,
    tax_amount: line.taxAmount,
    total_amount: line.totalAmount,
    department: line.department,
    job_ref: line.jobRef,
    remarks: line.remarks,
    created_at: line.createdAt
  })));

  PropertiesService.getScriptProperties().setProperty('PURCHASE_CACHE_VERSION', String(Date.now()));
  return { ok: true, poNo: poNo };
}

function purchaseUpdatePO(payload) {
  if (!payload || !payload.poNo) throw new Error('PO No is required');

  const header = _purchaseListPOHeaders_().find(row => row.poNo === String(payload.poNo || '').trim());
  if (!header) throw new Error('PO not found');
  if (_purchaseIsCancelledStatus_(header.status)) throw new Error('Cancelled purchase orders cannot be edited.');

  const vendor = _purchaseListVendors_().find(v => v.id === payload.vendorId);
  if (!vendor) throw new Error('Vendor not found');

  const livePO = ((purchaseListPOsJSON({ poNo: header.poNo, forceRefresh: true }).rows || [])[0]) || { lines: [] };
  const existingLines = _purchaseListPOLines_()
    .filter(line => line.poNo === header.poNo)
    .sort((a, b) => Number(a.lineNo || 0) - Number(b.lineNo || 0));
  const existingLiveMap = {};
  (livePO.lines || []).forEach(line => { existingLiveMap[String(line.id)] = line; });
  const incomingList = Array.isArray(payload.lines) ? payload.lines.filter(Boolean) : [];
  const incomingMap = {};
  incomingList.forEach(line => {
    if (!line || !line.id) return;
    incomingMap[String(line.id)] = line;
  });
  const incomingPrNos = [...new Set(
    incomingList.map(function(line) {
      return String(line && (line.prNo || line.sourceRef) || '').trim();
    })
    .concat(existingLines.map(function(line) {
      return String(line && line.sourceRef || '').trim();
    }))
    .filter(Boolean)
  )];
  const prMap = _purchaseGetInventoryPRValidationMap_(incomingPrNos);

  let totalQty = 0;
  let basicTotal = 0;
  let taxTotal = 0;
  const freightValue = Math.max(0, Number(payload.freightValue || 0));
  const finalLines = [];
  const isPlateDiePO = existingLines.some(function(line) {
    return _purchaseIsPlateDieSource_(line.sourceType);
  });
  const currentAllocatedByPr = {};
  existingLines.forEach(function(line) {
    if (String(line.sourceType || '').trim().toUpperCase() !== 'INVENTORY_PR') return;
    const prNo = String(line.sourceRef || '').trim();
    if (!prNo) return;
    currentAllocatedByPr[prNo] = Number(currentAllocatedByPr[prNo] || 0) + Number(line.qty || 0);
  });
  if (!isPlateDiePO) {
    const desiredQtyByPr = {};
    incomingList.forEach(function(line) {
      const sourceType = String(line && line.sourceType || '').trim().toUpperCase();
      const prNo = String(line && (line.prNo || line.sourceRef) || '').trim();
      if (sourceType !== 'INVENTORY_PR' || !prNo) return;
      desiredQtyByPr[prNo] = Number(desiredQtyByPr[prNo] || 0) + Number(line.qty || 0);
    });
    Object.keys(desiredQtyByPr).forEach(function(prNo) {
      const prCtx = prMap[prNo];
      if (!prCtx) throw new Error('PR not found: ' + prNo);
      _purchaseAssertPRCanGeneratePO_(prCtx, desiredQtyByPr[prNo], {
        currentAllocatedQty: Number(currentAllocatedByPr[prNo] || 0),
        allowExistingOnClosed: true
      });
    });
  }

  existingLines.forEach(line => {
    const incoming = incomingMap[String(line.id)];
    const live = existingLiveMap[String(line.id)] || {};
    if (!incoming) {
      if (Number(live.receivedQty || 0) > 0) {
        throw new Error('Cannot delete line ' + line.lineNo + ' because receipts already exist.');
      }
      supabaseDelete('purchase_order_lines', { id: 'eq.' + line.id });
      return;
    }
    const sourceType = String(incoming.sourceType || line.sourceType || '').trim().toUpperCase() || 'DIRECT';
    const hasReceipts = Number(live.receivedQty || 0) > 0;
    let next;
    if (!isPlateDiePO) {
      if (sourceType !== 'INVENTORY_PR' || !String(incoming.prNo || incoming.sourceRef || line.sourceRef || '').trim()) {
        throw new Error('Inventory purchase orders can only add lines from pending purchase requests.');
      }
      const prNo = String(incoming.prNo || incoming.sourceRef || line.sourceRef || '').trim();
      const prCtx = prMap[prNo];
      if (!prCtx) throw new Error('PR not found: ' + prNo);
      next = _purchaseNormalizeInventoryPRLine_(Object.assign({}, line, incoming, { sourceType: sourceType, prNo: prNo }), prCtx, finalLines.length + 1, header.poNo, line.createdAt || _purchaseNowIso_(), {
        keepId: true,
        createdAt: line.createdAt || _purchaseNowIso_(),
        currentAllocatedQty: Number(currentAllocatedByPr[prNo] || line.qty || 0),
        allowExistingOnClosed: true
      });
    } else {
      next = _purchaseNormalizeDirectLine_(Object.assign({}, line, incoming, { sourceType: sourceType }), sourceType, finalLines.length + 1, header.poNo, line.createdAt || _purchaseNowIso_(), { keepId: true });
    }
    if (hasReceipts) {
      if (Number(next.qty || 0) + 0.0001 < Number(live.receivedQty || 0)) {
        throw new Error('PO qty cannot be reduced below received qty for line ' + line.lineNo);
      }
      const changedCommercial =
        String(next.sourceType || '').trim().toUpperCase() !== String(line.sourceType || '').trim().toUpperCase() ||
        String(next.sourceRef || '').trim() !== String(line.sourceRef || '').trim() ||
        String(next.itemCode || '').trim().toUpperCase() !== String(line.itemCode || '').trim().toUpperCase() ||
        String(next.itemName || '').trim().toUpperCase() !== String(line.itemName || '').trim().toUpperCase() ||
        Math.abs(Number(next.rate || 0) - Number(line.rate || 0)) > 0.0001 ||
        Math.abs(Number(next.taxPct || 0) - Number(line.taxPct || 0)) > 0.0001;
      if (changedCommercial) {
        throw new Error('Received PO line ' + line.lineNo + ' cannot change item, source, rate, or GST after GRN activity.');
      }
    }
    next.id = line.id;
    next.poId = header.id;
    finalLines.push(next);
  });

  incomingList.filter(line => !line.id || !existingLines.some(x => String(x.id) === String(line.id))).forEach(line => {
    const sourceType = String(line.sourceType || '').trim().toUpperCase() || 'DIRECT';
    if (!isPlateDiePO) {
      if (sourceType !== 'INVENTORY_PR' || !String(line.prNo || line.sourceRef || '').trim()) {
        throw new Error('Inventory purchase orders can only add lines from pending purchase requests.');
      }
      const prNo = String(line.prNo || line.sourceRef || '').trim();
      const prCtx = prMap[prNo];
      if (!prCtx) throw new Error('PR not found: ' + prNo);
      const next = _purchaseNormalizeInventoryPRLine_(Object.assign({}, line, { id: '' }), prCtx, finalLines.length + 1, header.poNo, _purchaseNowIso_(), {
        currentAllocatedQty: Number(currentAllocatedByPr[prNo] || 0),
        allowExistingOnClosed: true
      });
      next.poId = header.id;
      finalLines.push(next);
      return;
    }
    const next = _purchaseNormalizeDirectLine_(Object.assign({}, line, { id: '' }), sourceType, finalLines.length + 1, header.poNo, _purchaseNowIso_());
    next.poId = header.id;
    finalLines.push(next);
  });

  if (!finalLines.length) throw new Error('At least one PO line is required');

  const existingLineIds = {};
  existingLines.forEach(function(row) {
    existingLineIds[String(row.id)] = true;
  });

  finalLines.forEach((line, idx) => {
    line.lineNo = idx + 1;
    totalQty += line.qty;
    basicTotal += line.amount;
    taxTotal += line.taxAmount;
    if (existingLineIds[String(line.id)]) {
      supabaseUpdate('purchase_order_lines', { id: 'eq.' + line.id }, {
        line_no: line.lineNo,
        source_type: line.sourceType,
        source_ref: line.sourceRef,
        item_code: line.itemCode,
        item_name: line.itemName,
        qty: line.qty,
        rate: line.rate,
        tax_pct: line.taxPct,
        amount: line.amount,
        tax_amount: line.taxAmount,
        total_amount: line.totalAmount,
        department: line.department,
        job_ref: line.jobRef,
        remarks: line.remarks
      });
    } else {
      let inserted = false;
      let lastInsertError = null;
      for (let attempt = 0; attempt < 3 && !inserted; attempt++) {
        const insertId = Utilities.getUuid();
        try {
          supabaseInsert('purchase_order_lines', {
            id: insertId,
            po_id: header.id,
            po_no: header.poNo,
            line_no: line.lineNo,
            source_type: line.sourceType,
            source_ref: line.sourceRef,
            item_code: line.itemCode,
            item_name: line.itemName,
            qty: line.qty,
            rate: line.rate,
            tax_pct: line.taxPct,
            amount: line.amount,
            tax_amount: line.taxAmount,
            total_amount: line.totalAmount,
            department: line.department,
            job_ref: line.jobRef,
            remarks: line.remarks,
            created_at: line.createdAt || _purchaseNowIso_()
          });
          line.id = insertId;
          inserted = true;
        } catch (err) {
          lastInsertError = err;
          if (String(err && err.message || '').indexOf('23505') === -1) throw err;
        }
      }
      if (!inserted) throw lastInsertError || new Error('Unable to insert new PO line.');
    }
  });

  try {
    const freightTax = _purchaseFreightTaxBreakup_(vendor.state, freightValue);
    supabaseUpdate('purchase_orders', { id: 'eq.' + header.id }, {
      vendor_id: vendor.id,
      vendor_name: vendor.vendorName,
      vendor_email: vendor.email || '',
      vendor_phone: vendor.phone || '',
      vendor_address: vendor.address || '',
      payment_terms: String(payload.paymentTerms || '').trim(),
      freight_terms: String(payload.freightTerms || '').trim(),
      freight_value: freightValue,
      delivery_terms: String(payload.deliveryTerms || '').trim(),
      notes: String(payload.notes || '').trim(),
      total_qty: Number(totalQty.toFixed(3)),
      basic_total: Number(basicTotal.toFixed(2)),
      tax_total: Number((taxTotal + freightTax.taxAmount).toFixed(2)),
      total_value: Number((basicTotal + taxTotal + freightValue + freightTax.taxAmount).toFixed(2)),
      updated_at: _purchaseNowIso_()
    });
  } catch (e) {
    throw new Error('Run purchase_freight_value_schema.sql in Supabase before updating freight-valued purchase orders.');
  }

  _purchaseUpdatePOStatus_(header.poNo);
  PropertiesService.getScriptProperties().setProperty('PURCHASE_CACHE_VERSION', String(Date.now()));
  return { ok: true, poNo: header.poNo };
}

function _purchaseUpdatePOStatus_(poNo) {
  const header = _purchaseGetPOHeaderByNo_(poNo);
  if (!header) return;
  if (_purchaseIsCancelledStatus_(header.status)) return;
  const lines = _purchaseListPOLinesForPO_(poNo);
  if (!lines.length) return;
  const receiptQtyByLine = _purchaseReceiptQtyByLineForPO_(poNo);
  const totalQty = lines.reduce(function(sum, row) {
    return sum + Number(row.qty || 0);
  }, 0);
  const receivedQty = lines.reduce(function(sum, row) {
    return sum + Number(receiptQtyByLine[String(row.id || '').trim()] || 0);
  }, 0);
  const shortClosedQty = lines.reduce(function(sum, row) {
    const lineReceivedQty = Number(receiptQtyByLine[String(row.id || '').trim()] || 0);
    return sum + Number(_purchasePOLineShortClosedQty_(row, lineReceivedQty) || 0);
  }, 0);
  const status = _purchaseDerivePOStatusWithShortClose_(totalQty, receivedQty, shortClosedQty);
  supabaseUpdate('purchase_orders', { id: 'eq.' + header.id }, {
    status: status,
    updated_at: _purchaseNowIso_()
  });
}

function purchaseShortClosePOLines(payload) {
  const poNo = String(payload && payload.poNo || '').trim();
  const lineIds = Array.isArray(payload && payload.lineIds)
    ? payload.lineIds.map(function(v) { return String(v || '').trim(); }).filter(Boolean)
    : [];
  const reason = String(payload && payload.reason || '').trim();
  const actor = String(payload && payload.closedBy || '').trim() || _invLifecycleActor_();
  if (!poNo) throw new Error('PO No is required');
  if (!lineIds.length) throw new Error('Select at least one PO line to short close');
  if (!reason) throw new Error('Short-close reason is required');

  const header = _purchaseGetPOHeaderByNo_(poNo);
  if (!header) throw new Error('PO not found');
  if (_purchaseIsCancelledStatus_(header.status)) throw new Error('Cancelled PO cannot be short closed');

  const po = ((purchaseListPOsJSON({ poNo: poNo, forceRefresh: true }).rows || [])[0]) || null;
  const liveLines = po && Array.isArray(po.lines) ? po.lines : [];
  const now = _purchaseNowIso_();
  const closed = [];

  lineIds.forEach(function(lineId) {
    const live = liveLines.find(function(line) {
      return String(line.id || '').trim() === lineId;
    });
    if (!live) throw new Error('PO line not found: ' + lineId);
    if (Number(live.pendingQty || 0) <= 0.0001) {
      throw new Error('No pending quantity available to short close for line ' + (live.lineNo || ''));
    }
    const existingRemark = String(live.remarks || '').trim();
    const marker = '[PO_SHORT_CLOSE qty=' + Number(live.pendingQty || 0).toFixed(6) +
      ' by=' + actor.replace(/\]/g, '') +
      ' at=' + now +
      ' reason=' + reason.replace(/\]/g, ')') + ']';
    supabaseUpdate('purchase_order_lines', { id: 'eq.' + lineId }, {
      remarks: [existingRemark, marker].filter(Boolean).join('\n')
    });
    closed.push({
      lineId: lineId,
      lineNo: live.lineNo,
      itemCode: live.itemCode,
      shortClosedQty: Number(live.pendingQty || 0)
    });
  });

  _purchaseUpdatePOStatus_(poNo);
  PropertiesService.getScriptProperties().setProperty('PURCHASE_CACHE_VERSION', String(Date.now()));
  return { ok: true, poNo: poNo, closed: closed };
}

function purchaseShortClosePO(payload) {
  const poNo = String(payload && payload.poNo || '').trim();
  if (!poNo) throw new Error('PO No is required');
  const po = ((purchaseListPOsJSON({ poNo: poNo, forceRefresh: true }).rows || [])[0]) || null;
  if (!po) throw new Error('PO not found');
  const pendingLineIds = (po.lines || [])
    .filter(function(line) { return Number(line.pendingQty || 0) > 0.0001; })
    .map(function(line) { return line.id; })
    .filter(Boolean);
  if (!pendingLineIds.length) throw new Error('No pending PO lines available for short close');
  return purchaseShortClosePOLines(Object.assign({}, payload || {}, { poNo: poNo, lineIds: pendingLineIds }));
}

function purchaseCancelPOs(payload) {
  const poNos = Array.isArray(payload && payload.poNos)
    ? [...new Set(payload.poNos.map(function(v) { return String(v || '').trim(); }).filter(Boolean))]
    : [];
  if (!poNos.length) throw new Error('Select at least one purchase order to cancel.');

  const headers = _purchaseListPOHeaders_().filter(function(header) {
    return poNos.indexOf(String(header.poNo || '').trim()) !== -1;
  });
  if (!headers.length) throw new Error('Selected purchase orders were not found.');

  const missing = poNos.filter(function(poNo) {
    return !headers.some(function(header) { return String(header.poNo || '') === poNo; });
  });
  if (missing.length) throw new Error('PO not found: ' + missing.join(', '));

  const actualReceiptQtyByPo = _purchaseActualReceiptQtyByPoNos_(poNos);

  const blocked = [];
  const cancellable = [];
  headers.forEach(function(header) {
    if (_purchaseIsCancelledStatus_(header.status)) return;
    const actualReceivedQty = Number(actualReceiptQtyByPo[String(header.poNo || '').trim()] || 0);
    if (actualReceivedQty > 0) {
      blocked.push(header.poNo);
      return;
    }
    cancellable.push(header);
  });

  if (blocked.length) {
    throw new Error('Cannot cancel PO(s) with received material: ' + blocked.join(', '));
  }
  if (!cancellable.length) {
    return { ok: true, cancelled: 0, skipped: headers.length };
  }

  const now = _purchaseNowIso_();
  const actor = String(payload && payload.cancelledBy || '').trim() || 'ERP User';
  const reason = String(payload && payload.reason || '').trim();
  cancellable.forEach(function(header) {
    const notes = String(header.notes || '').trim();
    const cancelNote = 'Cancelled on ' + now + ' by ' + actor + (reason ? ' | ' + reason : '');
    supabaseUpdate('purchase_orders', { id: 'eq.' + header.id }, {
      status: 'CANCELLED',
      notes: notes ? (notes + '\n' + cancelNote) : cancelNote,
      updated_at: now
    });
  });

  PropertiesService.getScriptProperties().setProperty('PURCHASE_CACHE_VERSION', String(Date.now()));
  return {
    ok: true,
    cancelled: cancellable.length,
    poNos: cancellable.map(function(header) { return header.poNo; })
  };
}

function purchaseReceivePOLine(payload) {
  if (!payload || !payload.poNo || !payload.lineId) {
    throw new Error('PO line reference is required');
  }

  const qty = Number(payload.qty || 0);
  const rate = Number(payload.rate || 0);
  if (qty <= 0 || rate <= 0) throw new Error('Receive qty and rate are required');

  const line = _purchaseGetPOLineById_(payload.poNo, payload.lineId);
  if (!line) throw new Error('PO line not found');
  const header = _purchaseGetPOHeaderByNo_(payload.poNo);
  if (header && _purchaseIsCancelledStatus_(header.status)) {
    throw new Error('Cancelled purchase orders cannot be received.');
  }

  const po = ((purchaseListPOsJSON({ poNo: payload.poNo }).rows || [])[0]) || null;
  const liveLine = (po?.lines || []).find(r => r.id === payload.lineId) || line;
  const pendingQty = Number(liveLine.pendingQty ?? (Number(line.qty || 0) - Number(liveLine.receivedQty || 0)));
  if (liveLine.isShortClosed === true || Number(liveLine.shortClosedQty || 0) > 0) {
    throw new Error('This PO line is short closed and cannot be received.');
  }
  if (!payload.allowOverReceipt && qty > pendingQty) {
    throw new Error('Receipt exceeds PO pending quantity');
  }

  invAppendLedger_({
    refType: 'PO-RECEIPT',
    refNo: payload.poNo,
    itemCode: line.itemCode,
    qtyIn: qty,
    rate: rate,
    location: payload.location || DEFAULT_LOCATION,
    department: line.department,
    remarks: 'PO Receipt ' + payload.poNo
  });

  refreshStockMV_();

  if (line.sourceType === 'INVENTORY_PR' && line.sourceRef) {
    const pr = supabaseSelect('inv_purchase_requests', {
      filters: { pr_no: 'eq.' + line.sourceRef },
      limit: 1
    })[0];

    if (pr) {
      const newReceived = Number(pr.received_qty || 0) + qty;
      const reqQty = Number(pr.requested_qty || 0);
      const newStatus = newReceived >= reqQty ? 'CLOSED' : 'OPEN';
      supabaseUpdate(
        'inv_purchase_requests',
        { pr_no: 'eq.' + line.sourceRef },
        { received_qty: newReceived, status: newStatus }
      );
    }
  }

  _purchaseUpdatePOStatus_(payload.poNo);
  PropertiesService.getScriptProperties().setProperty('PURCHASE_CACHE_VERSION', String(Date.now()));

  return { ok: true };
}

function purchaseReceiveArtworkPOLine(payload) {
  if (!payload || !payload.poNo || !payload.lineId) {
    throw new Error('PO line reference is required');
  }

  const qty = Number(payload.qty || 0);
  const rate = Number(payload.rate || 0);
  if (qty <= 0 || rate <= 0) throw new Error('Receive qty and rate are required');

  const line = _purchaseListPOLines_().find(row => row.poNo === payload.poNo && row.id === payload.lineId);
  if (!line) throw new Error('PO line not found');
  const header = _purchaseListPOHeaders_().find(row => row.poNo === payload.poNo);
  if (header && _purchaseIsCancelledStatus_(header.status)) {
    throw new Error('Cancelled purchase orders cannot be received.');
  }
  if (!_purchaseIsPlateDieSource_(line.sourceType)) {
    throw new Error('Receipts from this screen can only be posted for plate or die purchase order lines.');
  }

  const receiptQtyByLine = _purchaseReceiptQtyByLineForPO_(payload.poNo);
  const alreadyReceivedQty = Number(receiptQtyByLine[String(line.id || '').trim()] || 0);
  const pendingQty = Math.max(0, Number(line.qty || 0) - alreadyReceivedQty);

  if (!payload.allowOverReceipt && qty > pendingQty) {
    throw new Error('Receipt exceeds PO pending quantity');
  }

  const receiptId = Utilities.getUuid();
  try {
    _purchaseInsertPOReceipt_({
      id: receiptId,
      poId: line.poId || null,
      poNo: payload.poNo,
      poLineId: line.id,
      lineNo: line.lineNo,
      sourceType: line.sourceType,
      sourceRef: line.sourceRef,
      artworkNo: line.sourceRef || line.itemCode,
      itemCode: line.itemCode,
      jobRef: line.jobRef,
      soRefs: line.jobRef,
      receiptDate: payload.receiptDate || _purchaseIsoDate_(new Date()),
      challanNo: String(payload.challanNo || '').trim(),
      qty: qty,
      rate: rate,
      remarks: String(payload.remarks || '').trim(),
      createdAt: _purchaseNowIso_(),
      updatedAt: _purchaseNowIso_()
    });
  } catch (e) {
    throw new Error('Unable to post plate or die receipt: ' + (e.message || e));
  }

  _purchaseUpdatePOStatus_(payload.poNo);
  PropertiesService.getScriptProperties().setProperty('PURCHASE_CACHE_VERSION', String(Date.now()));
  return { ok: true, poNo: payload.poNo, receiptIds: [receiptId], receiptId: receiptId };
}

function purchaseReceiveArtworkPOBulk(payload) {
  if (!payload || !payload.poNo) {
    throw new Error('PO reference is required');
  }
  const inputLines = Array.isArray(payload.lines) ? payload.lines.filter(Boolean) : [];
  if (!inputLines.length) {
    throw new Error('Select at least one receipt line');
  }

  const baseLines = _purchaseListPOLinesForPO_(payload.poNo);
  if (!baseLines.length) {
    throw new Error('PO lines not found');
  }

  const header = _purchaseGetPOHeaderByNo_(payload.poNo);
  if (!header) throw new Error('PO not found');
  if (_purchaseIsCancelledStatus_(header.status)) {
    throw new Error('Cancelled purchase orders cannot be received.');
  }
  const receiptQtyByLine = _purchaseReceiptQtyByLineForPO_(payload.poNo);

  const prepared = inputLines.map(function(entry, idx) {
    const lineId = String(entry.lineId || '').trim();
    const qty = Number(entry.qty || 0);
    const rate = Number(entry.rate || 0);
    if (!lineId) throw new Error('PO line reference is required for selected receipt row ' + (idx + 1));
    if (qty <= 0 || rate <= 0) throw new Error('Receive qty and rate are required for selected receipt row ' + (idx + 1));

    const line = baseLines.find(function(row) { return row.id === lineId; });
    if (!line) throw new Error('PO line not found for selected receipt row ' + (idx + 1));
    if (!_purchaseIsPlateDieSource_(line.sourceType)) {
      throw new Error('Bulk receipt is available only for plate or die purchase order lines.');
    }

    const alreadyReceivedQty = Number(receiptQtyByLine[String(line.id || '').trim()] || 0);
    const pendingQty = Math.max(0, Number(line.qty || 0) - alreadyReceivedQty);
    if (!payload.allowOverReceipt && qty > pendingQty) {
      throw new Error('Receipt exceeds PO pending quantity for line ' + (line.lineNo || idx + 1));
    }

    return {
      id: Utilities.getUuid(),
      poId: line.poId || null,
      poNo: payload.poNo,
      poLineId: line.id,
      lineNo: line.lineNo,
      sourceType: line.sourceType,
      sourceRef: line.sourceRef,
      artworkNo: line.sourceRef || line.itemCode,
      itemCode: line.itemCode,
      jobRef: line.jobRef,
      soRefs: line.jobRef,
      receiptDate: entry.receiptDate || payload.receiptDate || _purchaseIsoDate_(new Date()),
      challanNo: String(entry.challanNo || payload.challanNo || '').trim(),
      qty: qty,
      rate: rate,
      remarks: String(entry.remarks || '').trim(),
      createdAt: _purchaseNowIso_(),
      updatedAt: _purchaseNowIso_()
    };
  });

  try {
    _purchaseBulkInsertPOReceipts_(prepared);
  } catch (e) {
    throw new Error('Unable to post bulk plate or die receipt: ' + (e.message || e));
  }

  _purchaseUpdatePOStatus_(payload.poNo);
  PropertiesService.getScriptProperties().setProperty('PURCHASE_CACHE_VERSION', String(Date.now()));
  return {
    ok: true,
    poNo: payload.poNo,
    receiptIds: prepared.map(function(row) { return row.id; }),
    challanNo: String(payload.challanNo || '').trim(),
    receiptDate: payload.receiptDate || ''
  };
}

function purchaseGetPOPrintData(poNo) {
  if (!poNo) throw new Error('PO number is required');
  try {
    const rows = supabaseSelect('v_purchase_po_print_lines', {
      filters: { po_no: 'eq.' + poNo },
      order: 'line_no.asc'
    }) || [];
    if (rows.length) {
      const first = rows[0] || {};
      const vendor = {
        id: String(first.vendor_id || '').trim(),
        vendorCode: String(first.vendor_code || '').trim(),
        vendorName: String(first.vendor_name || '').trim(),
        gstin: String(first.vendor_gstin || '').trim(),
        phone: String(first.vendor_phone || '').trim(),
        email: String(first.vendor_email || '').trim(),
        address: String(first.vendor_address || '').trim(),
        city: String(first.vendor_city || '').trim(),
        state: String(first.vendor_state || '').trim()
      };
      const intra = String(vendor.state || '').trim().toLowerCase() === String(PURCHASE_COMPANY.state || '').trim().toLowerCase();
      const freightValue = Number(first.freight_value || 0);
      const freightTax = _purchaseFreightTaxBreakup_(vendor.state, freightValue);
      let subtotal = 0, cgst = 0, sgst = 0, igst = 0, grandTotal = 0;

      const normalizedLines = rows.map(function(row) {
        const gstPct = Number(row.tax_pct || 0);
        const basicAmount = Number(row.amount || 0);
        const cgstPct = intra ? gstPct / 2 : 0;
        const sgstPct = intra ? gstPct / 2 : 0;
        const igstPct = intra ? 0 : gstPct;
        const cgstAmt = +(basicAmount * cgstPct / 100).toFixed(2);
        const sgstAmt = +(basicAmount * sgstPct / 100).toFixed(2);
        const igstAmt = +(basicAmount * igstPct / 100).toFixed(2);
        const netAmount = +(basicAmount + cgstAmt + sgstAmt + igstAmt).toFixed(2);

        subtotal += basicAmount;
        cgst += cgstAmt;
        sgst += sgstAmt;
        igst += igstAmt;
        grandTotal += netAmount;

        return {
          id: row.line_id,
          poId: row.po_id,
          poNo: row.po_no,
          lineNo: Number(row.line_no || 0),
          sourceType: row.source_type || '',
          sourceRef: row.source_ref || '',
          itemCode: row.item_code || '',
          itemName: row.item_name || '',
          qty: Number(row.qty || 0),
          rate: Number(row.rate || 0),
          taxPct: gstPct,
          amount: basicAmount,
          taxAmount: Number(row.tax_amount || 0),
          totalAmount: Number(row.total_amount || 0),
          department: row.department || '',
          jobRef: row.job_ref || '',
          remarks: row.remarks || '',
          hsnCode: row.hsn_code || '',
          stockUnit: row.stock_unit || '',
          gstPct: gstPct,
          cgstPct: cgstPct,
          sgstPct: sgstPct,
          igstPct: igstPct,
          cgstAmt: cgstAmt,
          sgstAmt: sgstAmt,
          igstAmt: igstAmt,
          basicAmount: basicAmount,
          netAmount: netAmount
        };
      });

      return {
        ok: true,
        company: PURCHASE_COMPANY,
        header: {
          poNo: first.po_no,
          orderDate: first.order_date || '',
          status: first.status || 'OPEN',
          createdBy: first.created_by || '',
          paymentTerms: first.payment_terms || '',
          freightTerms: first.freight_terms || '',
          freightValue: freightValue,
          freightGstPct: freightTax.gstPct,
          deliveryTerms: first.delivery_terms || '',
          notes: first.notes || '',
          modeOfTransport: 'By Road'
        },
        vendor: vendor,
        receiver: {
          name: PURCHASE_COMPANY.receiverName,
          address: PURCHASE_COMPANY.address,
          email: PURCHASE_COMPANY.email,
          state: PURCHASE_COMPANY.state,
          gstin: PURCHASE_COMPANY.gstin,
          pan: PURCHASE_COMPANY.pan,
          cin: PURCHASE_COMPANY.cin,
          contactNo: PURCHASE_COMPANY.landline
        },
        delivery: {
          name: PURCHASE_COMPANY.deliveryName,
          address: PURCHASE_COMPANY.address,
          gstin: PURCHASE_COMPANY.gstin
        },
        lines: normalizedLines,
        totals: {
          qty: normalizedLines.reduce(function(sum, row) { return sum + Number(row.qty || 0); }, 0),
          basicAmount: +subtotal.toFixed(2),
          cgstAmount: +(cgst + freightTax.cgstAmt).toFixed(2),
          sgstAmount: +(sgst + freightTax.sgstAmt).toFixed(2),
          igstAmount: +(igst + freightTax.igstAmt).toFixed(2),
          freightAmount: +freightValue.toFixed(2),
          freightTaxAmount: +freightTax.taxAmount.toFixed(2),
          freightGstPct: freightTax.gstPct,
          value: +(grandTotal + freightValue + freightTax.taxAmount).toFixed(2)
        },
        intrastate: intra
      };
    }
  } catch (err) {}

  const header = _purchaseListPOHeaders_().find(row => row.poNo === poNo);
  if (!header) throw new Error('PO not found');

  const vendor = _purchaseListVendors_().find(v => v.id === header.vendorId) || {};
  const poRows = purchaseListPOsJSON().rows || [];
  const po = poRows.find(r => r.poNo === poNo) || {};
  const lines = (po.lines || [])
    .slice()
    .sort((a, b) => Number(a.lineNo || 0) - Number(b.lineNo || 0));

  const itemCodes = [...new Set(lines.map(l => l.itemCode).filter(Boolean))];
  const itemMap = {};
  if (itemCodes.length) {
    (_supabaseSelectByKeyInBatches_('inv_items', '*', 'item_code', itemCodes, null, 40) || []).forEach(item => {
      itemMap[item.item_code] = item;
    });
  }

  const intra = String(vendor.state || '').trim().toLowerCase() === String(PURCHASE_COMPANY.state || '').trim().toLowerCase();
  const freightValue = Number(header.freightValue || 0);
  const freightTax = _purchaseFreightTaxBreakup_(vendor.state, freightValue);
  let subtotal = 0, cgst = 0, sgst = 0, igst = 0, grandTotal = 0;

  const normalizedLines = lines.map(line => {
    const item = itemMap[line.itemCode] || {};
    const gstPct = Number(line.taxPct || 0);
    const basicAmount = Number(line.amount || 0);
    const cgstPct = intra ? gstPct / 2 : 0;
    const sgstPct = intra ? gstPct / 2 : 0;
    const igstPct = intra ? 0 : gstPct;
    const cgstAmt = +(basicAmount * cgstPct / 100).toFixed(2);
    const sgstAmt = +(basicAmount * sgstPct / 100).toFixed(2);
    const igstAmt = +(basicAmount * igstPct / 100).toFixed(2);
    const netAmount = +(basicAmount + cgstAmt + sgstAmt + igstAmt).toFixed(2);

    subtotal += basicAmount;
    cgst += cgstAmt;
    sgst += sgstAmt;
    igst += igstAmt;
    grandTotal += netAmount;

    return Object.assign({}, line, {
      hsnCode: item.hsn_group || (_purchaseIsPlateDieSource_(line.sourceType) ? '' : ''),
      stockUnit: _purchaseIsPlateDieSource_(line.sourceType)
        ? 'PCS'
        : (item.unit || item.uom || item.stock_unit || item.uom_name || ''),
      gstPct: gstPct,
      cgstPct: cgstPct,
      sgstPct: sgstPct,
      igstPct: igstPct,
      cgstAmt: cgstAmt,
      sgstAmt: sgstAmt,
      igstAmt: igstAmt,
      basicAmount: basicAmount,
      netAmount: netAmount
    });
  });

  return {
    ok: true,
    company: PURCHASE_COMPANY,
    header: {
      poNo: header.poNo,
      orderDate: header.orderDate,
      status: header.status,
      createdBy: header.createdBy || '',
      paymentTerms: header.paymentTerms || '',
      freightTerms: header.freightTerms || '',
      freightValue: freightValue,
      freightGstPct: freightTax.gstPct,
      deliveryTerms: header.deliveryTerms || '',
      notes: header.notes || '',
      modeOfTransport: 'By Road'
    },
    vendor: vendor,
    receiver: {
      name: PURCHASE_COMPANY.receiverName,
      address: PURCHASE_COMPANY.address,
      email: PURCHASE_COMPANY.email,
      state: PURCHASE_COMPANY.state,
      gstin: PURCHASE_COMPANY.gstin,
      pan: PURCHASE_COMPANY.pan,
      cin: PURCHASE_COMPANY.cin,
      contactNo: PURCHASE_COMPANY.landline
    },
    delivery: {
      name: PURCHASE_COMPANY.deliveryName,
      address: PURCHASE_COMPANY.address,
      gstin: PURCHASE_COMPANY.gstin
    },
    lines: normalizedLines,
    totals: {
      qty: normalizedLines.reduce((sum, row) => sum + Number(row.qty || 0), 0),
      basicAmount: +subtotal.toFixed(2),
      cgstAmount: +(cgst + freightTax.cgstAmt).toFixed(2),
      sgstAmount: +(sgst + freightTax.sgstAmt).toFixed(2),
      igstAmount: +(igst + freightTax.igstAmt).toFixed(2),
      freightAmount: +freightValue.toFixed(2),
      freightTaxAmount: +freightTax.taxAmount.toFixed(2),
      freightGstPct: freightTax.gstPct,
      value: +(grandTotal + freightValue + freightTax.taxAmount).toFixed(2)
    },
    intrastate: intra
  };
}

function purchaseDashboardSummaryJSON(opts = {}) {
  const type = String(opts.type || 'PLATE').toUpperCase();
  try {
    const core = (supabaseSelect('v_purchase_dashboard_core_metrics', {
      limit: 1
    }) || [])[0] || null;
    const recentRows = supabaseSelect('v_purchase_order_summary', {
      select: 'po_no,order_date,vendor_name,status,total_value,pending_qty,created_at',
      order: 'order_date.desc,created_at.desc',
      limit: 8
    }) || [];
    const tooling = (supabaseSelect('v_purchase_tooling_pending_summary', {
      filters: { type: 'eq.' + type },
      limit: 1
    }) || [])[0] || null;
    if (core) {
      return {
        ok: true,
        metrics: {
          pendingReqCount: Number(core.pending_req_count || 0),
          pendingReqQty: +Number(core.pending_req_qty || 0).toFixed(3),
          openPOCount: Number(core.open_po_count || 0),
          openPOPendingQty: +Number(core.open_po_pending_qty || 0).toFixed(3),
          totalPOValue: +Number(core.total_po_value || 0).toFixed(2),
          openPOValue: +Number(core.open_po_value || 0).toFixed(2),
          activeVendors: Number(core.active_vendors || 0),
          platePendingCount: Number(tooling && tooling.pending_count || 0)
        },
        recentOrders: recentRows.map(function(row) {
          return {
            poNo: row.po_no || '',
            orderDate: row.order_date || '',
            vendorName: row.vendor_name || '',
            status: row.status || 'OPEN',
            totalValue: Number(row.total_value || 0),
            pendingQty: Number(row.pending_qty || 0)
          };
        }),
        pdType: type
      };
    }
  } catch (err) {}

  const vendors = _purchaseListVendors_();
  const orders = purchaseListPOSummariesJSON({}).rows || [];
  const openPOs = orders.filter(o => ['OPEN','PARTIAL'].includes(String(o.status || '').toUpperCase()));
  const requestRows = purchaseListInventoryRequestsJSON({ pendingOnly: false }).rows || [];
  const pendingReqRows = requestRows.filter(function(row) {
    return Number(row.availableToOrderQty || 0) > 0;
  });
  const pendingReqCount = pendingReqRows.length;
  const pendingReqQty = pendingReqRows.reduce(function(sum, row) {
    return sum + Number(row.availableToOrderQty || 0);
  }, 0);
  const pdKeySet = {};
  getPlateDieJobs({ pendingOnly: true, type: type }).forEach(function(row) {
    const key = String(row.artworkNo || '').trim() || (String(row.id || '') + '||' + String(row.lineNo || ''));
    if (key) pdKeySet[key] = true;
  });

  return {
    ok: true,
    metrics: {
      pendingReqCount: pendingReqCount,
      pendingReqQty: +pendingReqQty.toFixed(3),
      openPOCount: openPOs.length,
      openPOPendingQty: +openPOs.reduce((s, o) => s + Number(o.pendingQty || 0), 0).toFixed(3),
      totalPOValue: +orders.reduce((s, o) => s + Number(o.totalValue || 0), 0).toFixed(2),
      openPOValue: +openPOs.reduce((s, o) => s + Number(o.totalValue || 0), 0).toFixed(2),
      activeVendors: vendors.length,
      platePendingCount: Object.keys(pdKeySet).length
    },
    recentOrders: orders.slice(0, 8),
    pdType: type
  };
}

function purchaseBootstrapJSON(opts = {}) {
  const version = PropertiesService.getScriptProperties().getProperty('PURCHASE_CACHE_VERSION') || '0';
  const normalized = {
    requests: Object.assign({ status: '' }, opts.requests || {}),
    orders: opts.orders || {},
    leadTime: opts.leadTime || {},
    plateDie: opts.plateDie || {},
    include: Object.assign({
      vendors: true,
      dashboard: true,
      requests: true,
      orders: true,
      leadTime: false,
      plateDie: true
    }, opts.include || {})
  };
  const cacheKey = _cacheKeyHash_('PURCHASE_BOOTSTRAP', JSON.stringify({
    v: version,
    filters: normalized
  }));
  const cache = CacheService.getScriptCache();
  const cached = cache.get(cacheKey);
  if (cached) {
    try { return JSON.parse(cached); } catch (e) { cache.remove(cacheKey); }
  }

  const payload = { ok: true };
  if (normalized.include.vendors) payload.vendors = purchaseListVendorsJSON().rows;
  if (normalized.include.dashboard) payload.dashboard = purchaseDashboardSummaryJSON({ type: normalized.plateDie.type || 'PLATE' });
  if (normalized.include.requests) payload.requests = purchaseListInventoryRequestsJSON(normalized.requests).rows;
  if (normalized.include.orders) payload.orders = purchaseListPOSummariesJSON(normalized.orders).rows;
  if (normalized.include.leadTime) payload.leadTimeItems = purchaseListLeadTimeItemsJSON().rows;
  if (normalized.include.plateDie) payload.plateDieJobs = getPlateDieJobs(normalized.plateDie);
  try { cache.put(cacheKey, JSON.stringify(payload), 180); } catch (e) {}
  return payload;
}

/******************************************************
    Work Order Backend
 * PowerStik ERP
 ******************************************************/
function _fyString_(d) {
  const dt = d ? new Date(d) : new Date();
  const y = dt.getFullYear();
  const m = dt.getMonth() + 1;
  const fyStart = (m >= 4) ? y : (y - 1);
  const a = String(fyStart).slice(-2);
  const b = String(fyStart + 1).slice(-2);
  return a + '-' + b;
}

function _nextWOSeq_() {

  const seq = supabaseSelect('wo_sequence', {
    limit: 1
  })[0];

  if (!seq) {

    supabaseInsert('wo_sequence',{last_no:1});
    return 1;

  }

  const next = (seq.last_no || 0) + 1;

  supabaseUpdate(
    'wo_sequence',
    { id: 'eq.' + seq.id },
    { last_no: next }
  );

  return next;

}

function _formatWONo_(seq, d) {
  const fy = _fyString_(d);
  const num = ('00000' + seq).slice(-5);
  return 'J' + num + '/' + fy;
}

function _formatFlexoWONo_(seq, d) {
  const fy = _fyString_(d);
  const num = ('00000' + seq).slice(-5);
  return 'F' + num + '/' + fy;
}

function generateWorkOrderNumber() {
  const seq = _nextWOSeq_();
  return _formatWONo_(seq, new Date());
}

function generateFlexoWorkOrderNumber() {
  const seq = _nextWOSeq_();
  return _formatFlexoWONo_(seq, new Date());
}

function getNextWONumber() {
  return { woNo: generateWorkOrderNumber() };
}

function getNextFlexoWONumber() {
  return { woNo: generateFlexoWorkOrderNumber() };
}

function _workOrderDataVersion_() {
  return PropertiesService.getScriptProperties().getProperty('WORK_ORDER_DATA_VERSION') || '0';
}

function _touchWorkOrderDataVersion_() {
  PropertiesService.getScriptProperties().setProperty('WORK_ORDER_DATA_VERSION', String(Date.now()));
}

function _workOrderLoadCacheKey_(woNo) {
  return _cacheKeyHash_('WORK_ORDER_LOAD', _workOrderDataVersion_() + '|' + String(woNo || '').trim());
}

function _workOrderQueueCacheKey_(limit, offset) {
  return _cacheKeyHash_(
    'WORK_ORDER_QUEUE',
    _workOrderDataVersion_() + '|' + String(limit || '') + '|' + String(offset || '')
  );
}

function _workOrderQueueFastCacheKey_(request) {
  const r = request || {};
  return _cacheKeyHash_(
    'WORK_ORDER_QUEUE_FAST',
    _workOrderDataVersion_() + '|' + String(r.dateFrom || '') + '|' + String(r.dateTo || '')
  );
}

function _isMissingInventoryReservationsTable_(err) {
  const msg = String(err && err.message || err || '');
  return msg.indexOf('inventory_reservations') !== -1 &&
    (msg.indexOf('PGRST205') !== -1 ||
     msg.indexOf('Could not find the table') !== -1 ||
     msg.indexOf('schema cache') !== -1);
}

function _deleteInventoryReservationsForWO_(woNo) {
  if (!woNo) return;
  try {
    supabaseDelete('inventory_reservations', {
      reference_type: 'eq.WORK_ORDER',
      reference_no: 'eq.' + woNo
    });
  } catch (err) {
    if (_isMissingInventoryReservationsTable_(err)) {
      Logger.log('inventory_reservations table missing; skipping WO reservation delete for ' + woNo);
      return;
    }
    throw err;
  }
}

function _insertInventoryReservationForWO_(woNo, materialRow) {
  if (!woNo || !materialRow?.item_id) return;
  try {
    supabaseInsertMinimal('inventory_reservations', {
      item_id: materialRow.item_id,
      reference_type: 'WORK_ORDER',
      reference_no: woNo,
      reserved_qty: materialRow.required_qty,
      uom: materialRow.uom,
      created_at: new Date().toISOString()
    });
  } catch (err) {
    if (_isMissingInventoryReservationsTable_(err)) {
      Logger.log('inventory_reservations table missing; skipping WO reservation insert for ' + woNo);
      return;
    }
    throw err;
  }
}

/* =========================
   List SO with status (WO wizard)
   ========================= */
function _excludeCancelledSalesOrdersByNumber_(rows, soKey) {
  const list = _excludeManualBillingSalesOrdersByNumber_(rows, soKey);
  if (!list.length) return list;

  const keyName = soKey || 'so_number';
  const soNumbers = [...new Set(
    list
      .map(function(row) { return String(row && row[keyName] || '').trim(); })
      .filter(Boolean)
  )];

  if (!soNumbers.length) return list;

  const salesOrders = _supabaseSelectByKeyInBatches_(
    'sales_orders',
    'so_number,status',
    'so_number',
    soNumbers
  ) || [];

  const allowed = {};
  salesOrders.forEach(function(row) {
    const soNo = String(row.so_number || '').trim();
    allowed[soNo] = String(row.status || '').toUpperCase() !== 'CANCELLED';
  });

  return list.filter(function(row) {
    const soNo = String(row && row[keyName] || '').trim();
    return soNo && allowed[soNo] !== false;
  });
}

function _excludeClosedSalesOrderLines_(rows, soKey, lineKey) {
  const list = Array.isArray(rows) ? rows : [];
  if (!list.length) return list;

  const soName = soKey || 'so_number';
  const lineName = lineKey || 'line_no';
  const soNumbers = [...new Set(list.map(function(row) {
    return String(row && row[soName] || '').trim();
  }).filter(Boolean))];

  if (!soNumbers.length) return list;

  try {
    const soRows = _supabaseSelectByKeyInBatches_(
      'sales_orders',
      'id,so_number,status',
      'so_number',
      soNumbers,
      null,
      40
    ) || [];

    const soIdToNo = {};
    const cancelled = {};
    soRows.forEach(function(so) {
      const soNo = String(so.so_number || '').trim();
      const soId = String(so.id || '').trim();
      if (!soNo || !soId) return;
      soIdToNo[soId] = soNo;
      if (['CLOSED', 'CANCELLED'].indexOf(String(so.status || '').trim().toUpperCase()) !== -1) {
        cancelled[soNo] = true;
      }
    });

    const soIds = Object.keys(soIdToNo);
    if (!soIds.length) return list;

    const lineRows = _supabaseSelectByKeyInBatches_(
      'sales_order_lines',
      'so_id,line_no,status',
      'so_id',
      soIds,
      null,
      40
    ) || [];

    const blocked = {};
    lineRows.forEach(function(line) {
      const status = String(line.status || 'OPEN').trim().toUpperCase();
      if (status !== 'CLOSED' && status !== 'CANCELLED') return;
      const soNo = soIdToNo[String(line.so_id || '').trim()] || '';
      const lineNo = String(line.line_no || '').trim();
      if (soNo && lineNo) blocked[soNo + '||' + lineNo] = true;
    });

    return list.filter(function(row) {
      const soNo = String(row && row[soName] || '').trim();
      const lineNo = String(row && row[lineName] || '').trim();
      if (!soNo || !lineNo) return false;
      if (cancelled[soNo]) return false;
      return blocked[soNo + '||' + lineNo] !== true;
    });
  } catch (err) {
    const msg = String((err && err.message) || err || '');
    const missingStatus = msg.indexOf('sales_order_lines.status') !== -1 ||
      msg.indexOf('column sales_order_lines.status') !== -1 ||
      msg.indexOf('column "status" of relation "sales_order_lines" does not exist') !== -1;
    if (!missingStatus) throw err;
    Logger.log('sales_order_lines.status missing; closed-line filtering skipped until schema is applied.');
    return list;
  }
}

function _selectWorkOrderCandidateRows_(query) {
  try {
    return supabaseSelect('v_workorder_candidates_active', query) || [];
  } catch (err) {
    if (!_supabaseRelationMissing_(err, 'v_workorder_candidates_active')) throw err;
    return _excludeClosedSalesOrderLines_(supabaseSelect('v_workorder_candidates', query) || [], 'so_number', 'line_no');
  }
}

function _fetchWorkOrderCandidateRowsBySoNumbers_(soNumbers, select, order) {
  const list = [...new Set((soNumbers || []).map(function(soNo) {
    return String(soNo || '').trim();
  }).filter(Boolean))];
  if (!list.length) return [];

  try {
    return _supabaseSelectByKeyInBatches_(
      'v_workorder_candidates_active',
      select,
      'so_number',
      list,
      order,
      40
    ) || [];
  } catch (err) {
    if (!_supabaseRelationMissing_(err, 'v_workorder_candidates_active')) throw err;
    const rows = _supabaseSelectByKeyInBatches_(
      'v_workorder_candidates',
      select,
      'so_number',
      list,
      order,
      40
    ) || [];
    return _excludeClosedSalesOrderLines_(rows, 'so_number', 'line_no');
  }
}

function _isManualBillingSalesOrderRow_(row, soKey) {
  const keyName = soKey || 'so_number';
  const soNo = String(row && row[keyName] || '').trim().toUpperCase();
  const salesType = String(row && (row.sales_type || row.salesType) || '').trim().toUpperCase();
  const orderPrefix = String(row && (row.order_prefix || row.orderPrefix) || '').trim().toUpperCase();
  return orderPrefix === 'MB' || salesType === 'MANUAL_BILLING' || /^MB[\/-]/.test(soNo);
}

function _excludeManualBillingSalesOrdersByNumber_(rows, soKey) {
  const list = Array.isArray(rows) ? rows : [];
  if (!list.length) return list;
  return list.filter(function(row) {
    return !_isManualBillingSalesOrderRow_(row, soKey);
  });
}

function _workOrderProductionQty_(orderQty, stockQtyToBill) {
  return Math.max(0, (Number(orderQty || 0) || 0) - (Number(stockQtyToBill || 0) || 0));
}

function _opsLoadArtworkStockClosureRows_() {
  let artRows = [];
  try {
    artRows = supabaseSelect('artworks', {
      select: 'id,so_id,line_no,artwork_no,product_type,status,stock_qty_to_bill,approved_at',
      filters: {
        stock_qty_to_bill: 'gt.0',
        status: 'eq.APPROVED'
      },
      limit: 5000
    }) || [];
  } catch (err) {
    Logger.log('Artwork stock closure rows unavailable: ' + (err && err.message ? err.message : err));
    return { rows: [], byComposite: {}, soNumbers: [] };
  }
  if (!artRows.length) return { rows: [], byComposite: {}, soNumbers: [] };

  const soIds = [...new Set(artRows.map(function(row) { return row.so_id; }).filter(Boolean))];
  const soRows = _supabaseSelectByKeyInBatches_(
    'sales_orders',
    'id,so_number,status',
    'id',
    soIds
  ) || [];
  const soMap = {};
  soRows.forEach(function(row) {
    if (String(row.status || '').toUpperCase() === 'CANCELLED') return;
    soMap[String(row.id || '')] = row;
  });

  const lineRows = _supabaseSelectByKeyInBatches_(
    'sales_order_lines',
    'id,so_id,line_no,product_code,product_name,category,qty,accounts_status,business_status,product_remarks,prepress_remarks,expected_delivery,final_delivery,division,quote_no,pm_code',
    'so_id',
    soIds
  ) || [];
  const lineMap = {};
  lineRows.forEach(function(row) {
    lineMap[String(row.so_id || '') + '||' + String(row.line_no || '')] = row;
  });

  const rows = [];
  const byComposite = {};
  artRows.forEach(function(art) {
    const so = soMap[String(art.so_id || '')];
    if (!so || !so.so_number) return;
    const line = lineMap[String(art.so_id || '') + '||' + String(art.line_no || '')] || {};
    const key = String(so.so_number || '') + '||' + String(art.line_no || '');
    const qty = Math.max(0, Number(art.stock_qty_to_bill || 0) || 0);
    if (!qty || key === '||') return;
    const row = {
      key: key,
      soNumber: String(so.so_number || ''),
      lineNo: String(art.line_no || ''),
      soId: art.so_id || '',
      soLineId: line.id || '',
      productCode: line.product_code || '',
      productName: line.product_name || '',
      category: line.category || '',
      orderQty: Number(line.qty || 0),
      stockClosedQty: qty,
      artworkNo: art.artwork_no || '',
      productType: art.product_type || '',
      approvedAt: art.approved_at || '',
      line: line
    };
    rows.push(row);
    byComposite[key] = row;
  });

  return {
    rows: rows,
    byComposite: byComposite,
    soNumbers: [...new Set(rows.map(function(row) { return row.soNumber; }).filter(Boolean))]
  };
}

function _artworkStockAllocationMapBySoLine_(rows) {
  const list = Array.isArray(rows) ? rows : [];
  const soNumbers = [...new Set(list.map(function(row) {
    return String(row && (row.so_number || row.so) || '').trim();
  }).filter(Boolean))];
  if (!soNumbers.length) return {};

  const out = {};
  for (let i = 0; i < soNumbers.length; i += 40) {
    const chunk = soNumbers.slice(i, i + 40);
    (selectArtworkJobsView_({
      select: 'so_number,line_no,stock_qty_to_bill',
      filters: { so_number: _supabaseInFilter_(chunk) }
    }) || []).forEach(function(row) {
      const key = String(row.so_number || '') + '||' + String(row.line_no || '');
      if (key !== '||') out[key] = Number(row.stock_qty_to_bill || 0) || 0;
    });
  }
  return out;
}

function _applyArtworkStockAllocationToCandidateRows_(rows) {
  const list = Array.isArray(rows) ? rows : [];
  if (!list.length) return list;
  const allocationMap = _artworkStockAllocationMapBySoLine_(list);
  return list.map(function(row) {
    const key = String(row.so_number || row.so || '') + '||' + String(row.line_no || row.lineNo || '');
    if (Object.prototype.hasOwnProperty.call(allocationMap, key)) {
      row.stock_qty_to_bill = allocationMap[key];
    }
    return row;
  });
}

function _mapWOCandidateViewRow_(r) {
  const orderQty = Number(r.qty || 0) || 0;
  const stockQtyToBill = Math.max(0, Number(r.stock_qty_to_bill || 0) || 0);
  const qty = _workOrderProductionQty_(orderQty, stockQtyToBill);
  const processedQty = Number(r.processed_qty || 0) || 0;
  const viewRemaining = Number(r.remaining_qty != null ? r.remaining_qty : (qty - processedQty)) || 0;
  const remainingQty = stockQtyToBill > 0
    ? Math.max(0, qty - processedQty)
    : Math.max(0, viewRemaining);
  const canCreateWo = r.can_create_wo === true || String(r.can_create_wo || '').toLowerCase() === 'true';
  return {
    so: r.so_number || '',
    lineNo: String(r.line_no || ''),
    productCode: r.product_code || '',
    client: r.client_name || r.client_code || '',
    productName: r.product_name || '',
    artworkNo: r.artwork_no || '',
    qty: qty,
    orderQty: orderQty,
    stockQtyToBill: stockQtyToBill,
    remainingQty: remainingQty,
    processedQty: processedQty,
    unit: r.unit || '',
    category: r.category || '',
    productType: r.product_type || '',
    soDate: r.so_date || '',
    soTime: r.so_time || '',
    soDateTime: [r.so_date || '', r.so_time || ''].filter(Boolean).join(' '),
    salesRep: r.sales_rep || '',
    po_number: r.po_number || '',
    expected_delivery: r.expected_delivery || '',
    job_priority: r.job_priority || '',
    job_type: r.job_type || '',
    so_remarks: r.so_remarks || '',
    product_remarks: r.product_remarks || '',
    job_reference: r.job_reference || '',
    prepress_remark: r.prepress_remark || '',
    woList: r.wo_list || '',
    accountsStatus: String(r.accounts_status || '').trim().toUpperCase() || 'PENDING',
    businessStatus: String(r.business_status || '').trim().toUpperCase() || 'PENDING',
    artworkStatus: String(r.artwork_status || '').trim().toUpperCase() || 'NO_ART',
    approvalStage: r.approval_stage || 'Approved',
    canCreateWo: canCreateWo,
    artSheetLength: r.sheet_length == null ? '' : Number(r.sheet_length),
    artSheetWidth: r.sheet_width == null ? '' : Number(r.sheet_width),
    artSheetUps: r.sheet_ups == null ? '' : Number(r.sheet_ups),
    artPrintingColors: r.printing_colors || '',
    artAcrossUps: r.across_ups == null ? '' : Number(r.across_ups),
    artAlongUps: r.along_ups == null ? '' : Number(r.along_ups),
    artTotalUps: r.total_ups == null ? '' : Number(r.total_ups),
    artAcrossWidth: r.across_width == null ? '' : Number(r.across_width),
    artTeeth: r.teeth == null ? '' : Number(r.teeth),
    artAcrossGapMm: r.across_gap_mm == null ? '' : Number(r.across_gap_mm),
    artAlongGapMm: r.along_gap_mm == null ? '' : Number(r.along_gap_mm),
    artStatus: r.artwork_status || '',
    artApprovedAt: r.artwork_approved_at || null
  };
}

function _formatWorkOrderDateYMD_(date) {
  return Utilities.formatDate(date, Session.getScriptTimeZone() || 'Asia/Kolkata', 'yyyy-MM-dd');
}

function _normalizeWorkOrderDateYMD_(value) {
  const text = String(value || '').trim();
  return /^\d{4}-\d{2}-\d{2}$/.test(text) ? text : '';
}

function _defaultWorkOrderQueueDateRange_() {
  const to = new Date();
  const from = new Date(to.getTime());
  from.setDate(from.getDate() - 90);
  return {
    dateFrom: _formatWorkOrderDateYMD_(from),
    dateTo: _formatWorkOrderDateYMD_(to)
  };
}

function _normalizeWorkOrderQueueRequest_(arg, offset) {
  const defaults = _defaultWorkOrderQueueDateRange_();
  const req = (arg && typeof arg === 'object' && !Array.isArray(arg)) ? arg : {};
  let dateFrom = _normalizeWorkOrderDateYMD_(req.dateFrom) || defaults.dateFrom;
  let dateTo = _normalizeWorkOrderDateYMD_(req.dateTo) || defaults.dateTo;
  if (dateFrom && dateTo && dateFrom > dateTo) {
    const tmp = dateFrom;
    dateFrom = dateTo;
    dateTo = tmp;
  }
  return {
    dateFrom: dateFrom,
    dateTo: dateTo,
    forceRefresh: req.forceRefresh === true,
    legacyLimit: (arg && typeof arg !== 'object') ? Math.max(1, Number(arg || 0) || 200) : 0,
    legacyOffset: Math.max(0, Number(offset || 0) || 0)
  };
}

function _workOrderQueueSelect_() {
  return `
    so_number,
    so_date,
    so_time,
    sales_rep,
    client_code,
    client_name,
    line_no,
    product_code,
    product_name,
    category,
    qty,
    unit,
    po_number,
    expected_delivery,
    job_priority,
    job_type,
    so_remarks,
    product_remarks,
    prepress_remark,
    job_reference,
    accounts_status,
    business_status,
    artwork_no,
    product_type,
    stock_qty_to_bill,
    sheet_length,
    sheet_width,
    sheet_ups,
    printing_colors,
    across_ups,
    along_ups,
    total_ups,
    across_width,
    teeth,
    across_gap_mm,
    along_gap_mm,
    artwork_status,
    artwork_approved_at,
    processed_qty,
    remaining_qty,
    wo_list,
    approval_stage,
    can_create_wo,
    sales_type,
    order_prefix
  `;
}

function _workOrderQueueDateFilters_(dateFrom, dateTo) {
  if (dateFrom && dateTo) return { and: '(so_date.gte.' + dateFrom + ',so_date.lte.' + dateTo + ')' };
  if (dateFrom) return { so_date: 'gte.' + dateFrom };
  if (dateTo) return { so_date: 'lte.' + dateTo };
  return {};
}

function _workOrderQueueRpcMissing_(err) {
  const msg = String((err && err.message) || err || '').toLowerCase();
  return msg.indexOf('workorder_candidates_queue') !== -1 && (
    msg.indexOf('could not find') !== -1 ||
    msg.indexOf('does not exist') !== -1 ||
    msg.indexOf('schema cache') !== -1
  );
}

function _unwrapWorkOrderQueueRpc_(res) {
  if (!res) return null;
  if (Array.isArray(res)) {
    if (!res.length) return null;
    return res[0].workorder_candidates_queue || res[0].result || res[0];
  }
  return res.workorder_candidates_queue || res.result || res;
}

function _listSOWithStatusFromRpc_(req) {
  let payload = null;
  try {
    payload = _unwrapWorkOrderQueueRpc_(supabaseRpc('workorder_candidates_queue', {
      p_date_from: req.dateFrom || null,
      p_date_to: req.dateTo || null
    }));
  } catch (err) {
    if (_workOrderQueueRpcMissing_(err)) return null;
    console.warn('workorder_candidates_queue RPC failed; falling back to view fetch: ' + err);
    return null;
  }
  if (!payload || (!Array.isArray(payload.pending) && !Array.isArray(payload.processed))) return null;

  const pending = [];
  const processed = [];
  const pendingRows = _excludeManualBillingSalesOrdersByNumber_(payload.pending || [], 'so_number');
  const processedRows = _excludeManualBillingSalesOrdersByNumber_(payload.processed || [], 'so_number');

  pendingRows.forEach(function(r) {
    const row = _mapWOCandidateViewRow_(r);
    if (_isFlexoWorkOrderItem_(row)) return;
    if (row.remainingQty > 0) pending.push(row);
  });
  processedRows.forEach(function(r) {
    const row = _mapWOCandidateViewRow_(r);
    if (_isFlexoWorkOrderItem_(row)) return;
    if (row.processedQty > 0) processed.push(Object.assign({}, row, { qty: row.processedQty }));
  });

  return {
    pending: pending,
    processed: processed,
    hasMore: false,
    dateFrom: req.dateFrom,
    dateTo: req.dateTo
  };
}

function _listSOWithStatusFast_(request) {
  const req = _normalizeWorkOrderQueueRequest_(request);
  const rpcResult = _listSOWithStatusFromRpc_(req);
  if (rpcResult) return rpcResult;

  const rawRows = _selectWorkOrderCandidateRowsOptional_({
    select: _workOrderQueueSelect_(),
    filters: _workOrderQueueDateFilters_(req.dateFrom, req.dateTo),
    order: 'so_date.desc,so_number.desc,line_no.asc'
  }) || [];
  const rows = _excludeManualBillingSalesOrdersByNumber_(rawRows, 'so_number');
  const pending = [];
  const processed = [];

  rows.forEach(function(r) {
    const row = _mapWOCandidateViewRow_(r);
    if (_isFlexoWorkOrderItem_(row)) return;
    if (row.remainingQty > 0) pending.push(row);
    if (row.processedQty > 0) processed.push(Object.assign({}, row, { qty: row.processedQty }));
  });

  return {
    pending: pending,
    processed: processed,
    hasMore: false,
    dateFrom: req.dateFrom,
    dateTo: req.dateTo
  };
}

