    bill_to_address: selectedBillTo.address || '',
    bill_to_gstin: selectedBillTo.gstin || client.gstin || '',
    bill_to_state: selectedBillTo.state || client.state || '',
    ship_to_party_id: selectedShipTo.id || null,
